var surah011 = {
  number: 11,
  nameArabic: "Hud",
  nameEnglish: "Hud",
  meaning: "Hud",
  totalAyahs: 123,
  ayahs: [
    { number: 1, arabic: "الٓر ۚ كِتَٰبٌ أُحْكِمَتْ ءَايَٰتُهُۥ ثُمَّ فُصِّلَتْ مِن لَّدُنْ حَكِيمٍ خَبِيرٍ", transliteration: "Aliflamra kitabun ohkimat ayatuhu thumma fussilat min ladun hakeemin khabeerin", transliterationB: "Alif-Laaam-Raa; Kitaabun uhkimat Aayaatuhoo summa fussilat mil ladun Hakeemin Khabeer", english: "L. R. (This is) a Book, with verses basic or fundamental (of established meaning), further explained in detail,- from One Who is Wise and Well-acquainted (with all things)", romanUrdu: "Alif Laam Raa. Farmaan hai , jiski aayatin pukhta aur mufassal irshad hui hain, ek dana(wise) aur bakhabar hasti ki taraf se" },
    { number: 2, arabic: "أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۚ إِنَّنِى لَكُم مِّنْهُ نَذِيرٌۭ وَبَشِيرٌۭ", transliteration: "Alla taAAbudoo illa Allaha innanee lakum minhu natheerun wabasheerun", transliterationB: "Allaa ta'budooo illal laah; innanee lakum minhu nazeerunw wa basheer", english: "(It teacheth) that ye should worship none but Allah. (Say): \"Verily I am (sent) unto you from Him to warn and to bring glad tidings", romanUrdu: "Ke tum na bandagi karo magar sirf Allah ki. Main uski taraf se tumko khabardaar karne wala bhi hoon aur basharat dene wala bhi" },
    { number: 3, arabic: "وَأَنِ ٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ يُمَتِّعْكُم مَّتَٰعًا حَسَنًا إِلَىٰٓ أَجَلٍۢ مُّسَمًّۭى وَيُؤْتِ كُلَّ ذِى فَضْلٍۢ فَضْلَهُۥ ۖ وَإِن تَوَلَّوْا۟ فَإِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍۢ كَبِيرٍ", transliteration: "Waani istaghfiroo rabbakum thumma tooboo ilayhi yumattiAAkum mataAAan hasanan ila ajalin musamman wayuti kulla thee fadlin fadlahu wain tawallaw fainee akhafu AAalaykum AAathaba yawmin kabeerin", transliterationB: "Wa anis taghfiroo Rabbakum summa toobooo ilaihi yumatti'kum mataa'an hasanan ilaaa ajalim musammanw wa yu'ti kulla zee fadlin fadlahoo wa in tawallaw fa inneee akhaafu 'alaikum 'azaaba Yawmin Kabeer", english: "(And to preach thus), 'Seek ye the forgiveness of your Lord, and turn to Him in repentance; that He may grant you enjoyment, good (and true), for a term appointed, and bestow His abounding grace on all who abound in merit! But if ye turn away, then I fear for you the penalty of a great day", romanUrdu: "Aur yeh ke tum apne Rubb se maafi chaho aur uski taraf palat aao to woh ek khaas muddat tak tumko accha samaan e zindagi dega aur har sahib-e-fazl ko uska fazal ata karega. Lekin agar tum mooh pherte ho to main tumhare haqq mein ek baday haulnaak din ke azaab se darta hoon" },
    { number: 4, arabic: "إِلَى ٱللَّهِ مَرْجِعُكُمْ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ قَدِيرٌ", transliteration: "Ila Allahi marjiAAukum wahuwa AAala kulli shayin qadeerun", transliterationB: "Ilal laahi marji'ukum wa Huwa 'alaa kulli shai'in Qadeer", english: "To Allah is your return, and He hath power over all things", romanUrdu: "Tum sabko Allah ki taraf palatna hai aur woh sab kuch kar sakta hai" },
    { number: 5, arabic: "أَلَآ إِنَّهُمْ يَثْنُونَ صُدُورَهُمْ لِيَسْتَخْفُوا۟ مِنْهُ ۚ أَلَا حِينَ يَسْتَغْشُونَ ثِيَابَهُمْ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ", transliteration: "Ala innahum yathnoona sudoorahum liyastakhfoo minhu ala heena yastaghshoona thiyabahum yaAAlamu ma yusirroona wama yuAAlinoona innahu AAaleemun bithati alssudoori", transliterationB: "Alaa innahum yasnoona sudoorahum liyastakhfoo minh; alaa heena yastaghshoona siyaabahum ya'lamu maa yusiroona wa maa yu'linoon; innahoo 'aleemum bizaatis sudoor", english: "Behold! they fold up their hearts, that they may lie hid from Him! Ah even when they cover themselves with their garments, He knoweth what they conceal, and what they reveal: for He knoweth well the (inmost secrets) of the hearts", romanUrdu: "Dekho! Yeh log apne seeno ko moadte hain taa-ke ussey chup jayein. Khabardaar! Jab yeh kapdon se apne aap ko dhampte hain Allah unke chupe ko bhi jaanta hai aur khule ko bhi.Woh to un bhedon se bhi waqif hai jo seeno mein hain" },
    { number: 6, arabic: "۞ وَمَا مِن دَآبَّةٍۢ فِى ٱلْأَرْضِ إِلَّا عَلَى ٱللَّهِ رِزْقُهَا وَيَعْلَمُ مُسْتَقَرَّهَا وَمُسْتَوْدَعَهَا ۚ كُلٌّۭ فِى كِتَٰبٍۢ مُّبِينٍۢ", transliteration: "Wama min dabbatin fee alardi illa AAala Allahi rizquha wayaAAlamu mustaqarraha wamustawdaAAaha kullun fee kitabin mubeenin", transliterationB: "Wa maa min daaabbatin fil ardi illaa 'alal laahi rizquhaa wa ya'lamu mustaqarrahaa wa mustawda'ahaa; kullun fee Kitaabim Mubeen", english: "There is no moving creature on earth but its sustenance dependeth on Allah: He knoweth the time and place of its definite abode and its temporary deposit: All is in a clear Record", romanUrdu: "Zameen mein chalne wala koi jaandaar aisa nahin hai jiska rizq Allah ke zimme na ho aur jiske mutaaliq woh na jaanta ho ke kahan woh rehta hai aur kahan wo sompa jata hai, sab kuch ek saaf daftar mein darj hai" },
    { number: 7, arabic: "وَهُوَ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍۢ وَكَانَ عَرْشُهُۥ عَلَى ٱلْمَآءِ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًۭا ۗ وَلَئِن قُلْتَ إِنَّكُم مَّبْعُوثُونَ مِنۢ بَعْدِ ٱلْمَوْتِ لَيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَٰذَآ إِلَّا سِحْرٌۭ مُّبِينٌۭ", transliteration: "Wahuwa allathee khalaqa alssamawati waalarda fee sittati ayyamin wakana AAarshuhu AAala almai liyabluwakum ayyukum ahsanu AAamalan walain qulta innakum mabAAoothoona min baAAdi almawti layaqoolanna allatheena kafaroo in hatha illa sihrun mubeenun", transliterationB: "Wa Huwal lazee khalaqas samaawaati wal alrda fee sittati aiyaaminw wa kaana 'Arshuhoo alal maaa'i liyablu wakum aiyukum ahsanu 'amalaa; wa la'in qulta innakum mab'oosoona mim ba'dil mawti la yaqoolanal lazeena kafaroo in haazaaa illaa sihrum mubeen", english: "He it is Who created the heavens and the earth in six Days - and His Throne was over the waters - that He might try you, which of you is best in conduct. But if thou wert to say to them, \"Ye shall indeed be raised up after death\", the Unbelievers would be sure to say, \"This is nothing but obvious sorcery", romanUrdu: "Aur wahi hai jisne aasmano aur zameen ko chey (six) dino mein paida kiya jabke issey pehle uska arsh pani par tha taa-ke tumko aazma kar dekhe tum mein kaun behtar amal karne wala hai. Ab agar (aey Muhammad) tum kehte ho ke logon, marne ka baad tum dobara uthaye jaogey, to munkireen fawran bol uthte hain ke yeh to sareeh jaadugari hai" },
    { number: 8, arabic: "وَلَئِنْ أَخَّرْنَا عَنْهُمُ ٱلْعَذَابَ إِلَىٰٓ أُمَّةٍۢ مَّعْدُودَةٍۢ لَّيَقُولُنَّ مَا يَحْبِسُهُۥٓ ۗ أَلَا يَوْمَ يَأْتِيهِمْ لَيْسَ مَصْرُوفًا عَنْهُمْ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Walain akhkharna AAanhumu alAAathaba ila ommatin maAAdoodatin layaqoolunna ma yahbisuhu ala yawma yateehim laysa masroofan AAanhum wahaqa bihim ma kanoo bihi yastahzioona", transliterationB: "Wala'in akhkharnaa 'anhumul 'azaaba ilaaa ummatim ma'doodatil la yaqoolunna maa yahbisuh; alaa yawma yaateehim laisa masroofan 'anhum wa haaqa bihim maa kaanoo bihee yastahzi'oon", english: "If We delay the penalty for them for a definite term, they are sure to say, \"What keeps it back?\" Ah! On the day it (actually) reaches them, nothing will turn it away from them, and they will be completely encircled by that which they used to mock at", romanUrdu: "Aur agar hum ek khaas muddat tak unki saza ko taalte hain to woh kehne lagte hain ke aakhir kis cheez ne usey rok rakkha hai? Suno! Jis roz us saza ka waqt aa gaya to woh kisi ke phere na phir sakega aur wahi cheez unko aa gheregi jiska woh mazaq uda rahey hain" },
    { number: 9, arabic: "وَلَئِنْ أَذَقْنَا ٱلْإِنسَٰنَ مِنَّا رَحْمَةًۭ ثُمَّ نَزَعْنَٰهَا مِنْهُ إِنَّهُۥ لَيَـُٔوسٌۭ كَفُورٌۭ", transliteration: "Walain athaqna alinsana minna rahmatan thumma nazaAAnaha minhu innahu layaoosun kafoorun", transliterationB: "Wa la'in azaqnal insaana minnaa rahmatan summa naza'naahaa minhu, innahoo laya'oosun kafoor", english: "If We give man a taste of Mercy from Ourselves, and then withdraw it from him, behold! he is in despair and (falls into) blasphemy", romanUrdu: "Agar kabhi hum Insaan ko apni rehmat se nawazne ke baad phir ussey mehroom kardete hain to woh mayous hota hai aur nashukri karne lagta hai" },
    { number: 10, arabic: "وَلَئِنْ أَذَقْنَٰهُ نَعْمَآءَ بَعْدَ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ ذَهَبَ ٱلسَّيِّـَٔاتُ عَنِّىٓ ۚ إِنَّهُۥ لَفَرِحٌۭ فَخُورٌ", transliteration: "Walain athaqnahu naAAmaa baAAda darraa massathu layaqoolanna thahaba alssayyiatu AAannee innahu lafarihun fakhoorun", transliterationB: "Wala'in azaqnaahu na'maaa'a ba'da darraaa'a massat hu la yaqoolanna zahabas saiyiaatu 'anneee; innahoo lafarihun fakhoor", english: "But if We give him a taste of (Our) favours after adversity hath touched him, he is sure to say, \"All evil has departed from me:\" Behold! he falls into exultation and pride", romanUrdu: "Aur agar us museebat ke baad jo uspar aayi thi hum usey niyamat ka maza chakhate hain to kehta hai mere to sarey diladdar(sakhtiyan) paar ho gaye, phir woh phoola nahin samata aur akadne lagta hai" },
    { number: 11, arabic: "إِلَّا ٱلَّذِينَ صَبَرُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ أُو۟لَٰٓئِكَ لَهُم مَّغْفِرَةٌۭ وَأَجْرٌۭ كَبِيرٌۭ", transliteration: "Illa allatheena sabaroo waAAamiloo alssalihati olaika lahum maghfiratun waajrun kabeerun", transliterationB: "Illal lazeena sabaroo wa 'amilus saalihaati ulaaa'ika lahum maghfiratunw wa ajrun kabeer", english: "Not so do those who show patience and constancy, and work righteousness; for them is forgiveness (of sins) and a great reward", romanUrdu: "Is aieb se paak agar koi hain to bas woh log jo sabr karne waley hain aur neikokar hain aur wahi hain jinke liye darguzar bhi hai aur bada ajar bhi" },
    { number: 12, arabic: "فَلَعَلَّكَ تَارِكٌۢ بَعْضَ مَا يُوحَىٰٓ إِلَيْكَ وَضَآئِقٌۢ بِهِۦ صَدْرُكَ أَن يَقُولُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ كَنزٌ أَوْ جَآءَ مَعَهُۥ مَلَكٌ ۚ إِنَّمَآ أَنتَ نَذِيرٌۭ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍۢ وَكِيلٌ", transliteration: "FalaAAallaka tarikun baAAda ma yooha ilayka wadaiqun bihi sadruka an yaqooloo lawla onzila AAalayhi kanzun aw jaa maAAahu malakun innama anta natheerun waAllahu AAala kulli shayin wakeelun", transliterationB: "Fala'allaka taarikum ba'da maa yoohaaa ilaika wa daaa'iqum bihee sadruka ai yaqooloo law laaa unzila 'alaihi kanzun aw jaaa'a ma'ahoo malak; innamaa anta nazeer; wallaahu 'alaa kulli shai'inw wakeel", english: "Perchance thou mayest (feel the inclination) to give up a part of what is revealed unto thee, and thy heart feeleth straitened lest they say, \"Why is not a treasure sent down unto him, or why does not an angel come down with him?\" But thou art there only to warn! It is Allah that arrangeth all affairs", romanUrdu: "To aey paigambar! Kahin aisa na ho ke tum un cheezon mein se kisi cheez ko (bayan karne se) chodh do jo tumhari taraf wahee ki jaa rahi hai. Aur is baat par dil tangg ho ke woh kahenge “is shaks par koi khazana kyun na utara gaya” ya yeh ke “iske saath koi farishta kyun na aaya”. Tum to mehaz khabardaar karne waley ho, aagey har cheez ka hawaladaar Allah hai" },
    { number: 13, arabic: "أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ فَأْتُوا۟ بِعَشْرِ سُوَرٍۢ مِّثْلِهِۦ مُفْتَرَيَٰتٍۢ وَٱدْعُوا۟ مَنِ ٱسْتَطَعْتُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Am yaqooloona iftarahu qul fatoo biAAashri suwarin mithlihi muftarayatin waodAAoo mani istataAAtum min dooni Allahi in kuntum sadiqeena", transliterationB: "Am yaqooloonaf taraahu qul faatoo bi'ashri Suwarim mislihee muftarayaatinw wad'oo manis tata'tum min doonil laahi in kuntum saadiqeen", english: "Or they may say, \"He forged it,\" Say, \"Bring ye then ten suras forged, like unto it, and call (to your aid) whomsoever ye can, other than Allah!- If ye speak the truth", romanUrdu: "Kya yeh kehte hain ke paigmbar ne yeh kitab khud ghadh li hai? Kaho, “accha yeh baat hai to is jaisi ghadi hui dus suratein tum bana lao aur Allah ke siwa aur jo jo (tumhare mabood) hain unko madad ke liye bula sakte ho to bula lo agar tum (unhein mabood samajhne mein) sacchey ho" },
    { number: 14, arabic: "فَإِلَّمْ يَسْتَجِيبُوا۟ لَكُمْ فَٱعْلَمُوٓا۟ أَنَّمَآ أُنزِلَ بِعِلْمِ ٱللَّهِ وَأَن لَّآ إِلَٰهَ إِلَّا هُوَ ۖ فَهَلْ أَنتُم مُّسْلِمُونَ", transliteration: "Fai llam yastajeeboo lakum faiAAlamoo annama onzila biAAilmi Allahi waan la ilaha illa huwa fahal antum muslimoona", transliterationB: "Fa il lam yastajeeboo lakum fa'lamooo annamaaa unzilla bi'ilmil laahi wa al laaa ilaaha illaa Huwa fahal antum muslimoon", english: "If then they (your false gods) answer not your (call), know ye that this revelation is sent down (replete) with the knowledge of Allah, and that there is no god but He! will ye even then submit (to Islam)", romanUrdu: "Ab agar woh (tumhare mabood) tumhari madad ko nahin pahunchte to jaan lo ke yeh Allah ke ilm se nazil hui hai aur yeh ke Allah ke siwa koi haqiqi mabood nahin hai phir kya tum ( is amr e haqq ke aagey) sar-e-tasleem kham karte ho?”" },
    { number: 15, arabic: "مَن كَانَ يُرِيدُ ٱلْحَيَوٰةَ ٱلدُّنْيَا وَزِينَتَهَا نُوَفِّ إِلَيْهِمْ أَعْمَٰلَهُمْ فِيهَا وَهُمْ فِيهَا لَا يُبْخَسُونَ", transliteration: "Man kana yureedu alhayata alddunya wazeenataha nuwaffi ilayhim aAAmalahum feeha wahum feeha la yubkhasoona", transliterationB: "Man kaana yureedul hayaatad dunyaa zeenatahaa nuwaffi ilaihim a'maa lahum feehaa wa hum feehaa laa yubkhasoon", english: "Those who desire the life of the present and its glitter,- to them we shall pay (the price of) their deeds therein,- without diminution", romanUrdu: "Jo log bas isi duniya ki zindagi aur iski khush numaiyon ke taalib hotey hain unki kaarguzari ke sara phal hum yahin unko de dete hain aur ismein unke saath koi kami nahin ki jati" },
    { number: 16, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ لَيْسَ لَهُمْ فِى ٱلْءَاخِرَةِ إِلَّا ٱلنَّارُ ۖ وَحَبِطَ مَا صَنَعُوا۟ فِيهَا وَبَٰطِلٌۭ مَّا كَانُوا۟ يَعْمَلُونَ", transliteration: "Olaika allatheena laysa lahum fee alakhirati illa alnnaru wahabita ma sanaAAoo feeha wabatilun ma kanoo yaAAmaloona", transliterationB: "Ulaaa'ikal lazeena laisa lahum fil Aakhirati illan Naaru wa habita maa sana'oo feehaa wa baatilum maa kaanoo ya'maloon", english: "They are those for whom there is nothing in the Hereafter but the Fire: vain are the designs they frame therein, and of no effect and the deeds that they do", romanUrdu: "Magar aakhirat mein aisey logon ke liye aag ke siwa kuch nahin hai. (Wahan maloom ho jayega ke) jo kuch unhon ne duniya mein banaya woh sab maliyameit (worthless) hoga aur ab unka saara kiya dhara mehaz baatil hai" },
    { number: 17, arabic: "أَفَمَن كَانَ عَلَىٰ بَيِّنَةٍۢ مِّن رَّبِّهِۦ وَيَتْلُوهُ شَاهِدٌۭ مِّنْهُ وَمِن قَبْلِهِۦ كِتَٰبُ مُوسَىٰٓ إِمَامًۭا وَرَحْمَةً ۚ أُو۟لَٰٓئِكَ يُؤْمِنُونَ بِهِۦ ۚ وَمَن يَكْفُرْ بِهِۦ مِنَ ٱلْأَحْزَابِ فَٱلنَّارُ مَوْعِدُهُۥ ۚ فَلَا تَكُ فِى مِرْيَةٍۢ مِّنْهُ ۚ إِنَّهُ ٱلْحَقُّ مِن رَّبِّكَ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ", transliteration: "Afaman kana AAala bayyinatin min rabbihi wayatloohu shahidun minhu wamin qablihi kitabu moosa imaman warahmatan olaika yuminoona bihi waman yakfur bihi mina alahzabi faalnnaru mawAAiduhu fala taku fee miryatin minhu innahu alhaqqu min rabbika walakinna akthara alnnasi la yuminoona", transliterationB: "Afaman kaana 'alas baiyinatim mir Rabbihee wa yatloohu shaahidum minhu wa min qablihee Kitaabu Moosaaa imaamanw wa rahmah; ulaaa 'ika yu'minoona bih; wa mai yakfur bihee minal Ahzaabi fan Naaru maw'iduh; falaa taku fee miryatim minh; innahul haqqu mir Rabbika wa laakinna aksaran naasi laa yu'minoon", english: "Can they be (like) those who accept a Clear (Sign) from their Lord, and whom a witness from Himself doth teach, as did the Book of Moses before it,- a guide and a mercy? They believe therein; but those of the Sects that reject it,- the Fire will be their promised meeting-place. Be not then in doubt thereon: for it is the truth from thy Lord: yet many among men do not believe", romanUrdu: "Phir bhala woh shaks jo apne Rubb ki taraf se ek saaf shahadat(evidence) rakhta tha, iske baad ek gawah bhi parwardigar ki taraf se (is shahadat ki taeed mein) aa gaya, aur pehle Moosa ki kitab rehnuma aur rehmat ke taur par aayi hui bhi maujood thi (kya woh bhi duniya paraston ki tarah issey inkar kar sakta hai?) Aisey log to ispar iman hi layenge. Aur Insaani girohon mein se jo koi iska inkar karey to uske liye jis jagah ka wada hai woh dozakh hai. Pas (aey paigambar) , tum is cheez ki taraf se kisi shakk mein na padna, yeh haqq hai tumhare Rubb ki taraf se magar aksar log nahin maante" },
    { number: 18, arabic: "وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا ۚ أُو۟لَٰٓئِكَ يُعْرَضُونَ عَلَىٰ رَبِّهِمْ وَيَقُولُ ٱلْأَشْهَٰدُ هَٰٓؤُلَآءِ ٱلَّذِينَ كَذَبُوا۟ عَلَىٰ رَبِّهِمْ ۚ أَلَا لَعْنَةُ ٱللَّهِ عَلَى ٱلظَّٰلِمِينَ", transliteration: "Waman athlamu mimmani iftara AAala Allahi kathiban olaika yuAAradoona AAala rabbihim wayaqoolu alashhadu haolai allatheena kathaboo AAala rabbihim ala laAAnatu Allahi AAala alththalimeena", transliterationB: "Wa man azlamu mimmanif taraa 'alal laahi kazibaa; ulaaa'ika yu'radoona 'alaa Rabbihim wa yaqoolul ashhaa duhaaa'ulaaa'il lazeena kazaboo 'alaa Rabbihim; alaa la'natul laahi alaz zaalimeen", english: "Who doth more wrong than those who invent a life against Allah? They will be turned back to the presence of their Lord, and the witnesses will say, \"These are the ones who lied against their Lord! Behold! the Curse of Allah is on those who do wrong", romanUrdu: "aur us shaks se badh kar zalim aur kaun hoga jo Allah par jhoot ghaday? Aisey log apne Rubb ke huzoor pesh hongey aur gawah shahadat denge ke yeh hain woh log jinhon ne apne Rubb par jhoot ghada tha. Suno! khuda ki laanat hai zalimon par" },
    { number: 19, arabic: "ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًۭا وَهُم بِٱلْءَاخِرَةِ هُمْ كَٰفِرُونَ", transliteration: "Allatheena yasuddoona AAan sabeeli Allahi wayabghoonaha AAiwajan wahum bialakhirati hum kafiroona", transliterationB: "Allazeena yasuddoona 'an sabeelil laahi wa yabghoonahaa 'iwajanw wa hum bil Aakhiratihum kaafiroon", english: "Those who would hinder (men) from the path of Allah and would seek in it something crooked: these were they who denied the Hereafter", romanUrdu: "Un zalimon par jo khuda ke raaste se logon ko roakte hain, uske raaste ko teda karna chahte hain aur aakhirat ka inkar karte hain" },
    { number: 20, arabic: "أُو۟لَٰٓئِكَ لَمْ يَكُونُوا۟ مُعْجِزِينَ فِى ٱلْأَرْضِ وَمَا كَانَ لَهُم مِّن دُونِ ٱللَّهِ مِنْ أَوْلِيَآءَ ۘ يُضَٰعَفُ لَهُمُ ٱلْعَذَابُ ۚ مَا كَانُوا۟ يَسْتَطِيعُونَ ٱلسَّمْعَ وَمَا كَانُوا۟ يُبْصِرُونَ", transliteration: "Olaika lam yakoonoo muAAjizeena fee alardi wama kana lahum min dooni Allahi min awliyaa yudaAAafu lahumu alAAathabu ma kanoo yastateeAAoona alssamAAa wama kanoo yubsiroona", transliterationB: "Ulaaa'ika lam yakoonoo mu'jizeena fil ardi wa maa kaana lahum min doonil laahi min awliyaaa'; yudaa'afu lahumul 'azaab; maa kaanoo yastatee'oonas sam'a wa maa kaanoo yubsiroon", english: "They will in no wise frustrate (His design) on earth, nor have they protectors besides Allah! Their penalty will be doubled! They lost the power to hear, and they did not see", romanUrdu: "Woh zameen mein Allah ko bay-bas karne waley na thay aur na Allah ke muqable mein koi unka haami (protector) tha. Unhein ab dohra (double) azaab diya jayega. Woh na kisi ki sun hi sakte thay aur na khud hi unhein kuch soojhta tha" },
    { number: 21, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "Olaika allatheena khasiroo anfusahum wadalla AAanhum ma kanoo yaftaroona", transliterationB: "Ulaaa'ikal lazeena khasirooo anfusahum wa dalla 'anhum maa kaanoo yaftaroon", english: "They are the ones who have lost their own souls: and the (fancies) they invented have left them in the lurch", romanUrdu: "Yeh woh log hain jinhon ne apne aap ko khud ghaatey (nuksan) mein dala aur woh sab kuch unse khoya gaya jo unhon ne ghadh rakkha tha" },
    { number: 22, arabic: "لَا جَرَمَ أَنَّهُمْ فِى ٱلْءَاخِرَةِ هُمُ ٱلْأَخْسَرُونَ", transliteration: "La jarama annahum fee alakhirati humu alakhsaroona", transliterationB: "Laa jarama annahum fil Aakhirati humul akhsaroon", english: "Without a doubt, these are the very ones who will lose most in the Hereafter", romanUrdu: "Naguzeer hai ke wahi aakhirat mein sabse badhkar ghatey(loss) mein rahein" },
    { number: 23, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ وَأَخْبَتُوٓا۟ إِلَىٰ رَبِّهِمْ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Inna allatheena amanoo waAAamiloo alsalihati waakhbatoo ila rabbihim olaika ashabu aljannati hum feeha khalidoona", transliterationB: "Innal lazeena aamanoo wa 'amilus saalihaati wa akhbatooo ilaa Rabbihim ulaaa'ika Ashaabul Jannati hum feehaa khaalidoon", english: "But those who believe and work righteousness, and humble themselves before their Lord,- They will be companions of the gardens, to dwell therein for aye", romanUrdu: "Rahey woh log jo iman laye aur jinhon ne neik amal kiye aur apne Rubb hi ke hokar rahey, to yaqeenan woh jannati log hain aur jannat mein woh hamesha rahenge" },
    { number: 24, arabic: "۞ مَثَلُ ٱلْفَرِيقَيْنِ كَٱلْأَعْمَىٰ وَٱلْأَصَمِّ وَٱلْبَصِيرِ وَٱلسَّمِيعِ ۚ هَلْ يَسْتَوِيَانِ مَثَلًا ۚ أَفَلَا تَذَكَّرُونَ", transliteration: "Mathalu alfareeqayni kaalaAAma waalasammi waalbaseeri waalssameeAAi hal yastawiyani mathalan afala tathakkaroona", transliterationB: "Masalul fareeqini kal a'maa wal asammi walbaseeri wassamee'; hal yastawiyaani masalaa; afalaa tazakkaroon", english: "These two kinds (of men) may be compared to the blind and deaf, and those who can see and hear well. Are they equal when compared? Will ye not then take heed", romanUrdu: "In dono fareeqon ki misal aisi hai jaise ek aadmi to ho andha behra aur dursa ho dekhne aur sunne wala. Kya yeh dono yaksan ho sakte hain? Kya tum (is misaal se) koi sabaq nahin letey" },
    { number: 25, arabic: "وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦٓ إِنِّى لَكُمْ نَذِيرٌۭ مُّبِينٌ", transliteration: "Walaqad arsalna noohan ila qawmihi innee lakum natheerun mubeenun", transliterationB: "Wa laqad arsalnaa Noohan ilaa qawmihee innee lakum nazeerum mubeen", english: "We sent Noah to his people (with a mission): \"I have come to you with a Clear Warning", romanUrdu: "(aur aisey hi halaat thay jab) humne Nooh ko uski qaum ki taraf bhejha tha. (Usne kaha) “ main tum logon ko saaf saaf kahbardaar karta hoon" },
    { number: 26, arabic: "أَن لَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۖ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ أَلِيمٍۢ", transliteration: "An la taAAbudoo illa Allaha innee akhafu AAalaykum AAathaba yawmin aleemin", transliterationB: "Al laa ta'budooo illal laaha inneee akhaafu 'alaikum 'azaaba Yawmin aleem", english: "That ye serve none but Allah: Verily I do fear for you the penalty of a grievous day", romanUrdu: "ke Allah ke siwa kisi ki bandagi na karo, warna mujhey andesha hai ke tumpar ek roz dardnaak azaab aayega.”" },
    { number: 27, arabic: "فَقَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ مَا نَرَىٰكَ إِلَّا بَشَرًۭا مِّثْلَنَا وَمَا نَرَىٰكَ ٱتَّبَعَكَ إِلَّا ٱلَّذِينَ هُمْ أَرَاذِلُنَا بَادِىَ ٱلرَّأْىِ وَمَا نَرَىٰ لَكُمْ عَلَيْنَا مِن فَضْلٍۭ بَلْ نَظُنُّكُمْ كَٰذِبِينَ", transliteration: "Faqala almalao allatheena kafaroo min qawmihi ma naraka illa basharan mithlana wama naraka ittabaAAaka illa allatheena hum arathiluna badiya alrrayi wama nara lakum AAalayna min fadlin bal nathunnukum kathibeena", transliterationB: "Faqaalal mala ul lazeena kafaroo min qawmihee ma naraaka illaa basharam mislanaa wa maa naraakat taba'aka illal lazeena hum araazilunaa baadiyar raayi wa maa naraa lakum 'alainaa min fadlim bal nazunnukum kaazibeen", english: "But the chiefs of the Unbelievers among his people said: \"We see (in) thee nothing but a man like ourselves: Nor do we see that any follow thee but the meanest among us, in judgment immature: Nor do we see in you (all) any merit above us: in fact we think ye are liars", romanUrdu: "jawab mein uski qaum ke sardar, jinhon ne uski baat maanne se inkar kiya tha, bole “ hamari nazar mein to tum iske siwa kuch nahin ho ke bas ek Insaan ho hum jaise, aur hum dekh rahey hain ke hamari qaum mein se bas un logon ne jo hamare haan arazil thay(adna darje / lowliest) be-soochey samjhey tumhari pairwi ikhtiyar karli hai. Aur hum koi cheez bhi aisi nahin patey jis mein tumlog humse kuch badhey huye ho. Balke hum to tumhein jhoota samajhte hain”" },
    { number: 28, arabic: "قَالَ يَٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍۢ مِّن رَّبِّى وَءَاتَىٰنِى رَحْمَةًۭ مِّنْ عِندِهِۦ فَعُمِّيَتْ عَلَيْكُمْ أَنُلْزِمُكُمُوهَا وَأَنتُمْ لَهَا كَٰرِهُونَ", transliteration: "Qala ya qawmi araaytum in kuntu AAala bayyinatin min rabbee waatanee rahmatan min AAindihi faAAummiyat AAalaykum anulzimukumooha waantum laha karihoona", transliterationB: "Qaala yaa qawmi ara'aitum in kuntu 'alaa baiyinatim mir Rabbee wa aataanee rahmatam min 'indihee fa'um miyat 'alaikum anulzimuku moohaa wa antum lahaa kaarihoon", english: "He said: \"O my people! See ye if (it be that) I have a Clear Sign from my Lord, and that He hath sent Mercy unto me from His own presence, but that the Mercy hath been obscured from your sight? shall we compel you to accept it when ye are averse to it", romanUrdu: "Usne kaha “aey biradran e qaum, zara socho to sahih ke agar main apne Rubb ki taraf se ek khuli shahadat par qayam tha aur phir usne mujhko apni khaas rehmat se bhi nawaz diya, magar woh tumko nazar na aayi, to aakhir hamare paas kya zariya hai ke tum maanna na chaho aur hum zabardasti usko tumhare sar chapaik dein" },
    { number: 29, arabic: "وَيَٰقَوْمِ لَآ أَسْـَٔلُكُمْ عَلَيْهِ مَالًا ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۚ وَمَآ أَنَا۠ بِطَارِدِ ٱلَّذِينَ ءَامَنُوٓا۟ ۚ إِنَّهُم مُّلَٰقُوا۟ رَبِّهِمْ وَلَٰكِنِّىٓ أَرَىٰكُمْ قَوْمًۭا تَجْهَلُونَ", transliteration: "Waya qawmi la asalukum AAalayhi malan in ajriya illa AAala Allahi wama ana bitaridi allatheena amanoo innahum mulaqoo rabbihim walakinnee arakum qawman tajhaloona", transliterationB: "Wa yaa qawmi laaa as'alukum 'alaihi maalan in ajriya illaa 'alal laah; wa maaa ana bitaaridil lazeena aamanoo; innahum mulaaqoo Rabbihim wa laakinneee araakum qawman tajhaloon", english: "And O my people! I ask you for no wealth in return: my reward is from none but Allah: But I will not drive away (in contempt) those who believe: for verily they are to meet their Lord, and ye I see are the ignorant ones", romanUrdu: "Aur aey biradran e qaum, main is kaam par tumse koi maal nahin maangta , mera ajar to Allah ke zimme hai aur main un logon ko dhakke dene se bhi raha jinhon ne meri baat maani hai. Woh aap hi apne Rubb ke huzoor janey waley hain magar main dekhta hoon ke tumlog jahalat barat rahey ho" },
    { number: 30, arabic: "وَيَٰقَوْمِ مَن يَنصُرُنِى مِنَ ٱللَّهِ إِن طَرَدتُّهُمْ ۚ أَفَلَا تَذَكَّرُونَ", transliteration: "Waya qawmi man yansurunee mina Allahi in taradtuhum afala tathakkaroona", transliterationB: "Wa yaa qawmi mai yansurunee minal laahi in tarattuhum; afalaa tazak karoon", english: "And O my people! who would help me against Allah if I drove them away? Will ye not then take heed", romanUrdu: "Aur aey qaum, main in logon ko dhutkaar doon to khuda ki pakad se kaun mujhey bachane aayega? Tum logon ki samajh mein kya itni baat bhi nahin aati" },
    { number: 31, arabic: "وَلَآ أَقُولُ لَكُمْ عِندِى خَزَآئِنُ ٱللَّهِ وَلَآ أَعْلَمُ ٱلْغَيْبَ وَلَآ أَقُولُ إِنِّى مَلَكٌۭ وَلَآ أَقُولُ لِلَّذِينَ تَزْدَرِىٓ أَعْيُنُكُمْ لَن يُؤْتِيَهُمُ ٱللَّهُ خَيْرًا ۖ ٱللَّهُ أَعْلَمُ بِمَا فِىٓ أَنفُسِهِمْ ۖ إِنِّىٓ إِذًۭا لَّمِنَ ٱلظَّٰلِمِينَ", transliteration: "Wala aqoolu lakum AAindee khazainu Allahi wala aAAlamu alghayba wala aqoolu innee malakun wala aqoolu lillatheena tazdaree aAAyunukum lan yutiyahumu Allahu khayran Allahu aAAlamu bima fee anfusihim innee ithan lamina alththalimeena", transliterationB: "Wa laa aqoolu lakum 'indee khazaa'inul laahi wa laaa a'lamul ghaiba wa laa aqoolu inee malakunw wa laaa aqoolu lillazeena tazdareee a'yunukum lai yu'tiyahumul laahu khairan Allaahu a'lamu bimaa feee anfusihim innee izal laminaz zaalimeen", english: "I tell you not that with me are the treasures of Allah, nor do I know what is hidden, nor claim I to be an angel. Nor yet do I say, of those whom your eyes do despise that Allah will not grant them (all) that is good: Allah knoweth best what is in their souls: I should, if I did, indeed be a wrong-doer", romanUrdu: "Aur main tumse nahin kehta ke mere paas Allah ke khazane hain, na yeh kehte hoon ke main gaib ka ilm rakhta hoon, na yeh mera dawa hai ke main farishta hoon aur yeh bhi main nahin keh sakta ke jin logon ko tumhari aankhein hikarat se dekhti hain unhein Allah ne koi bhalayi nahin di. Unke nafs ka haal Allah hi behtar jaanta hai. Agar main aisa kahoon to zalim honga”" },
    { number: 32, arabic: "قَالُوا۟ يَٰنُوحُ قَدْ جَٰدَلْتَنَا فَأَكْثَرْتَ جِدَٰلَنَا فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Qaloo ya noohu qad jadaltana faaktharta jidalana fatina bima taAAiduna in kunta mina alssadiqeena", transliterationB: "Qaaloo yaa Noohu qad jaadaltanaa fa aksarta jidaalanaa faatinaa bimaa ta'idunaaa in kunta minas saadiqeen", english: "They said: \"O Noah! thou hast disputed with us, and (much) hast thou prolonged the dispute with us: now bring upon us what thou threatenest us with, if thou speakest the truth", romanUrdu: "Aakhir e kaar un logon ne kaha ke “ aey Nooh, tumne humse jhagda kiya aur bahut karliya ab to bas woh azaab le aao jiski tum humein dhamki dete ho agar sacchey ho”" },
    { number: 33, arabic: "قَالَ إِنَّمَا يَأْتِيكُم بِهِ ٱللَّهُ إِن شَآءَ وَمَآ أَنتُم بِمُعْجِزِينَ", transliteration: "Qala innama yateekum bihi Allahu in shaa wama antum bimuAAjizeena", transliterationB: "Qaala innamaa yaateekum bihil laahu in shaaa'a wa maaa antum bimu'jizeen", english: "He said: \"Truly, Allah will bring it on you if He wills,- and then, ye will not be able to frustrate it", romanUrdu: "Nooh ne jawab diya,“ woh to Allah hi layega , agar chahega, aur tum itna bal-boota nahin rakhte ke isey roak do" },
    { number: 34, arabic: "وَلَا يَنفَعُكُمْ نُصْحِىٓ إِنْ أَرَدتُّ أَنْ أَنصَحَ لَكُمْ إِن كَانَ ٱللَّهُ يُرِيدُ أَن يُغْوِيَكُمْ ۚ هُوَ رَبُّكُمْ وَإِلَيْهِ تُرْجَعُونَ", transliteration: "Wala yanfaAAukum nushee in aradtu an ansaha lakum in kana Allahu yureedu an yughwiyakum huwa rabbukum wailayhi turjaAAoona", transliterationB: "Wa laa yanfa'ukum nusheee in arattu an ansaha lakum in kaanal laahu yureedu ai yughwi yakum; Huwa Rabbukum wa ilaihi turja'oon", english: "Of no profit will be my counsel to you, much as I desire to give you (good) counsel, if it be that Allah willeth to leave you astray: He is your Lord! and to Him will ye return", romanUrdu: "Ab agar main tumhari kuch khair khwahi karna bhi chahoon to meri khair khwahi tumhein koi faiyda nahin de sakti jabke Allah hi ne tumhein bhatka dene ka irada karliya ho. Wahi tumahra Rubb hai aur usi ki taraf tumhein palatna hai”" },
    { number: 35, arabic: "أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ إِنِ ٱفْتَرَيْتُهُۥ فَعَلَىَّ إِجْرَامِى وَأَنَا۠ بَرِىٓءٌۭ مِّمَّا تُجْرِمُونَ", transliteration: "Am yaqooloona iftarahu qul ini iftaraytuhu faAAalayya ijramee waana bareeon mimma tujrimoona", transliterationB: "Am yaqooloonaf taraahu qul inif taraituhoo fa'alaiya ijraamee wa ana bareee'um mimmaa tujrimoon", english: "Or do they say, \"He has forged it\"? Say: \"If I had forged it, on me were my sin! and I am free of the sins of which ye are guilty", romanUrdu: "(Aey Muhammad),kya yeh log kehte hain ke is shaks ne yeh sab kuch khud ghadh(forged) liya hai?Insey kaho “ agar maine yeh khud ghada hai to mujhpar apne jurm ki zimmedari hai, aur jo jurm tum kar rahey ho uski zimmedari se main bari hoon.”" },
    { number: 36, arabic: "وَأُوحِىَ إِلَىٰ نُوحٍ أَنَّهُۥ لَن يُؤْمِنَ مِن قَوْمِكَ إِلَّا مَن قَدْ ءَامَنَ فَلَا تَبْتَئِسْ بِمَا كَانُوا۟ يَفْعَلُونَ", transliteration: "Waoohiya ila noohin annahu lan yumina min qawmika illa man qad amana fala tabtais bima kanoo yafAAaloona", transliterationB: "Wa oohiya ilaa Noohin annahoo lany-yu'mina min qawmika illaa man qad aamana falaa tabta'is bimaa kaanoo yaf'aloon", english: "It was revealed to Noah: \"None of thy people will believe except those who have believed already! So grieve no longer over their (evil) deeds", romanUrdu: "Nooh par wahee ki gayi ke tumhari qaum mein se jo log iman laa chuke bas woh laa chuke, ab koi maanne wala nahin hai. Inke kartooton par ghum khana chodo" },
    { number: 37, arabic: "وَٱصْنَعِ ٱلْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَا وَلَا تُخَٰطِبْنِى فِى ٱلَّذِينَ ظَلَمُوٓا۟ ۚ إِنَّهُم مُّغْرَقُونَ", transliteration: "WaisnaAAi alfulka biaAAyunina wawahyina wala tukhatibnee fee allatheena thalamoo innahum mughraqoona", transliterationB: "Wasna'il fulka bi-a'yuninaa wa wahyinaa wa laa tukhaa tibnee fil lazeena zalamoo; innahum mughraqoon", english: "But construct an Ark under Our eyes and Our inspiration, and address Me no (further) on behalf of those who are in sin: for they are about to be overwhelmed (in the Flood)", romanUrdu: "Aur hamari nigrani mein hamari wahee ke mutabiq ek kashti banani shuru kardo. Aur dekho, jin logon ne zulm kiya hai unke haqq mein mujhse koi sifarish na karna. Yeh sarey ke sarey ab doobne waley hain" },
    { number: 38, arabic: "وَيَصْنَعُ ٱلْفُلْكَ وَكُلَّمَا مَرَّ عَلَيْهِ مَلَأٌۭ مِّن قَوْمِهِۦ سَخِرُوا۟ مِنْهُ ۚ قَالَ إِن تَسْخَرُوا۟ مِنَّا فَإِنَّا نَسْخَرُ مِنكُمْ كَمَا تَسْخَرُونَ", transliteration: "WayasnaAAu alfulka wakullama marra AAalayhi malaon min qawmihi sakhiroo minhu qala in taskharoo minna fainna naskharu minkum kama taskharoona", transliterationB: "Wa yasn'ul fulka wa kullamaa marra 'alaihi malaum min qawmihee sakhiroo minh; qaala in taskharoo minnaa fa innaa naskharu minkum kamaa taskharoon", english: "Forthwith he (starts) constructing the Ark: Every time that the chiefs of his people passed by him, they threw ridicule on him. He said: \"If ye ridicule us now, we (in our turn) can look down on you with ridicule likewise", romanUrdu: "Nooh kashti bana raha tha aur uski qaum ke sardaron mein se jo koi uske paas se guzarta tha woh uska mazaaq udata tha. Usne kaha “ agar tum humpar haste ho to hum bhi tumpar hass rahey hain" },
    { number: 39, arabic: "فَسَوْفَ تَعْلَمُونَ مَن يَأْتِيهِ عَذَابٌۭ يُخْزِيهِ وَيَحِلُّ عَلَيْهِ عَذَابٌۭ مُّقِيمٌ", transliteration: "Fasawfa taAAlamoona man yateehi AAathabun yukhzeehi wayahillu AAalayhi AAathabun muqeemun", transliterationB: "Fasawfa ta'lamoona mai yaateehi 'azaabuny yaukhzeehi wa yahillu 'alaihi 'azaabum muqeem", english: "But soon will ye know who it is on whom will descend a penalty that will cover them with shame,- on whom will be unloosed a penalty lasting", romanUrdu: "Anqareeb tumhein khud maloom ho jayega ke kis par woh azaab aata hai jo usey ruswa kardega, aur kispar woh balaa toot padti hai jo taley nahin taleygi”" },
    { number: 40, arabic: "حَتَّىٰٓ إِذَا جَآءَ أَمْرُنَا وَفَارَ ٱلتَّنُّورُ قُلْنَا ٱحْمِلْ فِيهَا مِن كُلٍّۢ زَوْجَيْنِ ٱثْنَيْنِ وَأَهْلَكَ إِلَّا مَن سَبَقَ عَلَيْهِ ٱلْقَوْلُ وَمَنْ ءَامَنَ ۚ وَمَآ ءَامَنَ مَعَهُۥٓ إِلَّا قَلِيلٌۭ", transliteration: "Hatta itha jaa amruna wafara alttannooru qulna ihmil feeha min kullin zawjayni ithnayni waahlaka illa man sabaqa AAalayhi alqawlu waman amana wama amana maAAahu illa qaleelun", transliterationB: "Hattaaa izaa jaaa'a amrunaa wa faarat tannooru qulnah mil feehaa min kullin zawjainis naini wa ahlaka illaa man sabaqa 'alaihil qawlu wa man aaman; wa maaa aamana ma'ahooo illaa qaleel", english: "At length, behold! there came Our command, and the fountains of the earth gushed forth! We said: \"Embark therein, of each kind two, male and female, and your family - except those against whom the word has already gone forth,- and the Believers.\" but only a few believed with him", romanUrdu: "Yahan tak ke jab hamara hukum aa gaya aur woh tannoor (oven) ubal pada. To humne kaha “ har qism ke jaanwaron ka ek ek joda kashti mein rakh lo , apne ghar walon ko bhi siwaye un ashkaas ke jinki nishaan-dahi pehle ki jaa chuki hai is mein sawaar kara do, aur un logon ko bhi bitha lo jo imaan laaye hain”. Aur thode hi log thay jo Nooh ke saath iman laye thay" },
    { number: 41, arabic: "۞ وَقَالَ ٱرْكَبُوا۟ فِيهَا بِسْمِ ٱللَّهِ مَجْر۪ىٰهَا وَمُرْسَىٰهَآ ۚ إِنَّ رَبِّى لَغَفُورٌۭ رَّحِيمٌۭ", transliteration: "Waqala irkaboo feeha bismi Allahi majraha wamursaha inna rabbee laghafoorun raheemun", transliterationB: "Wa qaalar kaboo feehaa bismil laahi majraihaa wa mursaahaa; inna Rabbee la Ghafoorur Raheem", english: "So he said: \"Embark ye on the Ark, In the name of Allah, whether it move or be at rest! For my Lord is, be sure, Oft-Forgiving, Most Merciful", romanUrdu: "Nooh ne kaha “sawaar ho jao ismein , Allah hi ke naam se hai iska chalna bhi aur iska theharna bhi. Mera Rubb bada gafoor o raheem hai”" },
    { number: 42, arabic: "وَهِىَ تَجْرِى بِهِمْ فِى مَوْجٍۢ كَٱلْجِبَالِ وَنَادَىٰ نُوحٌ ٱبْنَهُۥ وَكَانَ فِى مَعْزِلٍۢ يَٰبُنَىَّ ٱرْكَب مَّعَنَا وَلَا تَكُن مَّعَ ٱلْكَٰفِرِينَ", transliteration: "Wahiya tajree bihim fee mawjin kaaljibali wanada noohunu ibnahu wakana fee maAAzilin ya bunayya irkab maAAana wala takun maAAa alkafireena", transliterationB: "Wa hiya tajree bihim fee mawjin kaljibaali wa naadaa Noohunib nahoo wa kaana fee ma'ziliny yaa bunai yarkam ma'anaa wa laa takum ma'al kaafireen", english: "So the Ark floated with them on the waves (towering) like mountains, and Noah called out to his son, who had separated himself (from the rest): \"O my son! embark with us, and be not with the unbelievers", romanUrdu: "kashti un logon ko liye chali jaa rahi thi aur ek ek mauj pahad ki tarah uth rahi thi. Nooh ka beta door faasle par tha, Nooh ne pukar kar kaha “beta , hamare saath sawaar hoja, kafiron ke saath na reh.”" },
    { number: 43, arabic: "قَالَ سَـَٔاوِىٓ إِلَىٰ جَبَلٍۢ يَعْصِمُنِى مِنَ ٱلْمَآءِ ۚ قَالَ لَا عَاصِمَ ٱلْيَوْمَ مِنْ أَمْرِ ٱللَّهِ إِلَّا مَن رَّحِمَ ۚ وَحَالَ بَيْنَهُمَا ٱلْمَوْجُ فَكَانَ مِنَ ٱلْمُغْرَقِينَ", transliteration: "Qala saawee ila jabalin yaAAsimunee mina almai qala la AAasima alyawma min amri Allahi illa man rahima wahala baynahuma almawju fakana mina almughraqeena", transliterationB: "Qaala sa aaweee ilaa jabaliny ya'simunee minal maaa'; qaala laa 'aasimal yawma min amril laahi illaa mar rahim; wa haala bainahumal mawju fakaana minal mughraqeen", english: "The son replied: \"I will betake myself to some mountain: it will save me from the water.\" Noah said: \"This day nothing can save, from the command of Allah, any but those on whom He hath mercy! \"And the waves came between them, and the son was among those overwhelmed in the Flood", romanUrdu: "usne palat kar jawab diya “main abhi ek pahad par chadha jata hoon jo mujhey pani se bacha lega”. Nooh ne kaha, aaj koi cheez Allah ke hukum se bachane wali nahin hai siwaye iske ke Allah hi kisi par reham farmaye”. Itne mein ek mauj dono ke darmiyan hayal ho gayi aur woh bhi doobne walon mein shamil ho gaya" },
    { number: 44, arabic: "وَقِيلَ يَٰٓأَرْضُ ٱبْلَعِى مَآءَكِ وَيَٰسَمَآءُ أَقْلِعِى وَغِيضَ ٱلْمَآءُ وَقُضِىَ ٱلْأَمْرُ وَٱسْتَوَتْ عَلَى ٱلْجُودِىِّ ۖ وَقِيلَ بُعْدًۭا لِّلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Waqeela ya ardu iblaAAee maaki waya samao aqliAAee wagheeda almao waqudiya alamru waistawat AAala aljoodiyyi waqeela buAAdan lilqawmi alththalimeena", transliterationB: "Wa qeela yaaa ardubla'ee maaa'aki wa yaa samaaa'u aqi'ee wa gheedal maaa'u wa qudiyal amru wastawat 'alal joodiyyi wa qeela bu'dal lilqawmiz zaalimeen", english: "Then the word went forth: \"O earth! swallow up thy water, and O sky! Withhold (thy rain)!\" and the water abated, and the matter was ended. The Ark rested on Mount Judi, and the word went forth: \"Away with those who do wrong", romanUrdu: "Hukum hua “aey zameen, apna saara paani ningal ja aur aey aasmaan, ruk ja” chunanchey pani zameen mein baith gaya , faisla chuka diya gaya, kashti judi par tik gayi, aur keh diya gaya ke door huyi zalimon ki qaum" },
    { number: 45, arabic: "وَنَادَىٰ نُوحٌۭ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبْنِى مِنْ أَهْلِى وَإِنَّ وَعْدَكَ ٱلْحَقُّ وَأَنتَ أَحْكَمُ ٱلْحَٰكِمِينَ", transliteration: "Wanada noohun rabbahu faqala rabbi inna ibnee min ahlee wainna waAAdaka alhaqqu waanta ahkamu alhakimeena", transliterationB: "Wa naadaa noohur Rabbahoo faqaala Rabbi innabnee min ahlee wa inna wa'dakal haqqu wa Anta ahkamul haakimeen", english: "And Noah called upon his Lord, and said: \"O my Lord! surely my son is of my family! and Thy promise is true, and Thou art the justest of Judges", romanUrdu: "Nooh ne apne Rubb ko pukara , kaha “Aey Rubb! mera beta mere ghar walon mein se hai aur tera wada saccha hai aur tu sab hakimo se bada aur behtar hakim hai”" },
    { number: 46, arabic: "قَالَ يَٰنُوحُ إِنَّهُۥ لَيْسَ مِنْ أَهْلِكَ ۖ إِنَّهُۥ عَمَلٌ غَيْرُ صَٰلِحٍۢ ۖ فَلَا تَسْـَٔلْنِ مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ ۖ إِنِّىٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلْجَٰهِلِينَ", transliteration: "Qala ya noohu innahu laysa min ahlika innahu AAamalun ghayru salihin fala tasalni ma laysa laka bihi AAilmun innee aAAithuka an takoona mina aljahileena", transliterationB: "Qaala yaa Noohu innahoo laisa min ahlika innahoo 'amalun ghairu saalihin falaa tas'alni mmaa laisa laka bihee 'ilmun inneee a'izuka an takoona minal jaahileen", english: "He said: \"O Noah! He is not of thy family: For his conduct is unrighteous. So ask not of Me that of which thou hast no knowledge! I give thee counsel, lest thou act like the ignorant", romanUrdu: "Jawab mein irshad hua “aey Nooh, woh tere ghar walon mein se nahin hai. Woh to ek bigda hua kaam hai. Lihaza tu us baat ki mujhse darkhwast na kar jiski haqeeqat tu nahin jaanta. Main tujhey naseehat karta hoon ke apne aap ko jaahilon ki tarah na bana le”" },
    { number: 47, arabic: "قَالَ رَبِّ إِنِّىٓ أَعُوذُ بِكَ أَنْ أَسْـَٔلَكَ مَا لَيْسَ لِى بِهِۦ عِلْمٌۭ ۖ وَإِلَّا تَغْفِرْ لِى وَتَرْحَمْنِىٓ أَكُن مِّنَ ٱلْخَٰسِرِينَ", transliteration: "Qala rabbi innee aAAoothu bika an asalaka ma laysa lee bihi AAilmun wailla taghfir lee watarhamnee akun mina alkhasireena", transliterationB: "Qaala rabbi inneee a'oozu bika an as'alaka maa laisa lee bihee 'ilmunw wa illaa taghfir lee wa tarhamneee akum minal khaasireen", english: "Noah said: \"O my Lord! I do seek refuge with Thee, lest I ask Thee for that of which I have no knowledge. And unless thou forgive me and have Mercy on me, I should indeed be lost", romanUrdu: "Nooh ne fawran arz kiya “Aey mere Rubb, main teri panaah maangta hoon issey ke woh cheez tujhse maangoon jiska mujhey ilam nahin. Agar tu nay mujhey maaf na kiya aur reham na farmaya to main barbaad ho jaunga" },
    { number: 48, arabic: "قِيلَ يَٰنُوحُ ٱهْبِطْ بِسَلَٰمٍۢ مِّنَّا وَبَرَكَٰتٍ عَلَيْكَ وَعَلَىٰٓ أُمَمٍۢ مِّمَّن مَّعَكَ ۚ وَأُمَمٌۭ سَنُمَتِّعُهُمْ ثُمَّ يَمَسُّهُم مِّنَّا عَذَابٌ أَلِيمٌۭ", transliteration: "Qeela ya noohu ihbit bisalamin minna wabarakatin AAalayka waAAala omamin mimman maAAaka waomamun sanumattiAAuhum thumma yamassuhum minna AAathabun aleemun", transliterationB: "Qeela yaa Noohuh bit bisalaamim minnaa wa barakaatin 'alaika wa 'alaaa umamim mimmam ma'ak; wa umamun sanumatti'uhum summa yamassuhum minaa 'azaabun aleem", english: "The word came: \"O Noah! Come down (from the Ark) with peace from Us, and blessing on thee and on some of the peoples (who will spring) from those with thee: but (there will be other) peoples to whom We shall grant their pleasures (for a time), but in the end will a grievous penalty reach them from Us", romanUrdu: "Hukum hua “ aey Nooh utar jaa hamari taraf se salamati aur barkatein hain tujhpar aur un girohon par jo tere saath hain. Aur kuch giroh aisey bhi hain jinko hum kuch muddat samaan e zindagi bakshenge phir unhein hamari taraf se dardnaak azaab pahunchega”" },
    { number: 49, arabic: "تِلْكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهَآ إِلَيْكَ ۖ مَا كُنتَ تَعْلَمُهَآ أَنتَ وَلَا قَوْمُكَ مِن قَبْلِ هَٰذَا ۖ فَٱصْبِرْ ۖ إِنَّ ٱلْعَٰقِبَةَ لِلْمُتَّقِينَ", transliteration: "Tilka min anbai alghaybi nooheeha ilayka ma kunta taAAlamuha anta wala qawmuka min qabli hatha faisbir inna alAAaqibata lilmuttaqeena", transliterationB: "Tilka min ambaaa'il ghaibi nooheehaaa ilaika maa kunta ta'lamuhaaaa anta wa laa qawmuka min qabli haazaa fasbir innal 'aaqibata lilmuttaqeen", english: "Such are some of the stories of the unseen, which We have revealed unto thee: before this, neither thou nor thy people knew them. So persevere patiently: for the End is for those who are righteous", romanUrdu: "(Aey Muhammad), yeh gaib ki khabrein hain jo hum tumhari taraf wahee kar rahey hain, issey pehle na tum inko jantey thay aur na tumhari qaum. Pas sabr karo, anjaam-e-kaar muttaqiyon ke haqq mein hai" },
    { number: 50, arabic: "وَإِلَىٰ عَادٍ أَخَاهُمْ هُودًۭا ۚ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۖ إِنْ أَنتُمْ إِلَّا مُفْتَرُونَ", transliteration: "Waila AAadin akhahum hoodan qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu in antum illa muftaroona", transliterationB: "Wa ilaa 'aadin akhaahum Hoodaa; qaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuhooo in antum illaa muftaroon", english: "To the 'Ad People (We sent) Hud, one of their own brethren. He said: \"O my people! worship Allah! ye have no other god but Him. (Your other gods) ye do nothing but invent", romanUrdu: "Aur Aad ki taraf humne unke bhai Hud ko bheja. Usne kaha “aey biradraan e qaum, Allah ki bandagi karo, tumhara koi khuda uske siwa nahin hai, tumne mehaz jhoot ghadh rakkhey hai" },
    { number: 51, arabic: "يَٰقَوْمِ لَآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱلَّذِى فَطَرَنِىٓ ۚ أَفَلَا تَعْقِلُونَ", transliteration: "Ya qawmi la asalukum AAalayhi ajran in ajriya illa AAala allathee fataranee afala taAAqiloona", transliterationB: "Yaa qawmi laaa as'alukum 'alaihi ajran in ajriya illaa 'alal lazee fataranee; afalaa ta'qiloon", english: "O my people! I ask of you no reward for this (Message). My reward is from none but Him who created me: Will ye not then understand", romanUrdu: "Aey biradraan e qaum is kaam par main tumse koi ajar nahin chahta. Mera ajar to uske zimme hai jisne mujhey paida kiya hai. Kya tum aqal se zara kaam nahin letey" },
    { number: 52, arabic: "وَيَٰقَوْمِ ٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ يُرْسِلِ ٱلسَّمَآءَ عَلَيْكُم مِّدْرَارًۭا وَيَزِدْكُمْ قُوَّةً إِلَىٰ قُوَّتِكُمْ وَلَا تَتَوَلَّوْا۟ مُجْرِمِينَ", transliteration: "Waya qawmi istaghfiroo rabbakum thumma tooboo ilayhi yursili alssamaa AAalaykum midraran wayazidkum quwwatan ila quwwatikum wala tatawallaw mujrimeena", transliterationB: "Wa yaa qawmis taghfiroo Rabbakum summa toobooo ilaihi yursilis samaaa'a 'alaikum midraaranw wa yazidkum quwwatan ilaa quwwatikum wa laa tatawallaw mujrimeen", english: "And O my people! Ask forgiveness of your Lord, and turn to Him (in repentance): He will send you the skies pouring abundant rain, and add strength to your strength: so turn ye not back in sin", romanUrdu: "Aur aey meri qaum ke logon, apne Rubb se mafi chaho, phir uski taraf palato. Woh tumpar aasmaan ke dahane khol dega aur tumhari maujooda quwwat(strength) par mazeed quwwat ka izafa karega. Mujreemon ki tarah mooh na phero”" },
    { number: 53, arabic: "قَالُوا۟ يَٰهُودُ مَا جِئْتَنَا بِبَيِّنَةٍۢ وَمَا نَحْنُ بِتَارِكِىٓ ءَالِهَتِنَا عَن قَوْلِكَ وَمَا نَحْنُ لَكَ بِمُؤْمِنِينَ", transliteration: "Qaloo ya hoodu ma jitana bibayyinatin wama nahnu bitarikee alihatina AAan qawlika wama nahnu laka bimumineena", transliterationB: "Qaaloo yaa Hoodu maa ji'tanaa bibaiyinatinw wa maa nahnu bitaarikeee aalihatinaa 'an qawlika wa maa nahnu laka bimu'mineen", english: "They said: \"O Hud! No Clear (Sign) that hast thou brought us, and we are not the ones to desert our gods on thy word! Nor shall we believe in thee", romanUrdu: "Unhon ne jawab diya, “aey Hud, tu hamare paas koi sareeh shahadat(evidence) lekar nahin aaya hai, aur tere kehne se hum apne maboodon ko nahin chodh sakte. Aur tujhpar hum iman laney waley nahin hain" },
    { number: 54, arabic: "إِن نَّقُولُ إِلَّا ٱعْتَرَىٰكَ بَعْضُ ءَالِهَتِنَا بِسُوٓءٍۢ ۗ قَالَ إِنِّىٓ أُشْهِدُ ٱللَّهَ وَٱشْهَدُوٓا۟ أَنِّى بَرِىٓءٌۭ مِّمَّا تُشْرِكُونَ", transliteration: "In naqoolu illa iAAtaraka baAAdu alihatina bisooin qala innee oshhidu Allaha waishhadoo annee bareeon mimma tushrikoona", transliterationB: "In naqoolu illa' taraaka ba'du aalihatinaa bisooo'; qaala inneee ushhidul laaha wash hadooo annee bareee'um mimmaa tushrikoon", english: "We say nothing but that (perhaps) some of our gods may have seized thee with imbecility.\" He said: \"I call Allah to witness, and do ye bear witness, that I am free from the sin of ascribing, to Him", romanUrdu: "Hum to yeh samajhte hain ke tere upar hamare maboodon mein se kisi ki maar padh gayi hai”. Hud ne kaha, “main Allah ki shahadat pesh karta hoon aur tum gawah raho ke yeh jo Allah ke siwa dusron ko tumne khudayi mein shareek thehra rakkha hai ussey main bezaar hoon" },
    { number: 55, arabic: "مِن دُونِهِۦ ۖ فَكِيدُونِى جَمِيعًۭا ثُمَّ لَا تُنظِرُونِ", transliteration: "Min doonihi fakeedoonee jameeAAan thumma la tunthirooni", transliterationB: "Min doonihee fakeedoonee jamee'an summa laa tunziroon", english: "Other gods as partners! so scheme (your worst) against me, all of you, and give me no respite", romanUrdu: "Tum sab ke sab milkar mere khilaf apne karni mein kasar na uttha rakkho aur mujhey zara mohlat na do" },
    { number: 56, arabic: "إِنِّى تَوَكَّلْتُ عَلَى ٱللَّهِ رَبِّى وَرَبِّكُم ۚ مَّا مِن دَآبَّةٍ إِلَّا هُوَ ءَاخِذٌۢ بِنَاصِيَتِهَآ ۚ إِنَّ رَبِّى عَلَىٰ صِرَٰطٍۢ مُّسْتَقِيمٍۢ", transliteration: "Innee tawakkaltu AAala Allahi rabbee warabbikum ma min dabbatin illa huwa akhithun binasiyatiha inna rabbee AAala siratin mustaqeemin", transliterationB: "Innee tawakkaltu 'alallaahi Rabbee wa Rabbikum; maa min daaabbatin illaa Huwa aakhizum binaasiyatihaa; inna Rabbee 'alaa Siraatim mustaqeem", english: "I put my trust in Allah, My Lord and your Lord! There is not a moving creature, but He hath grasp of its fore-lock. Verily, it is my Lord that is on a straight Path", romanUrdu: "Mera bharosa Allah par hai jo mera Rubb bhi hai aur tumhara Rubb bhi. Koi jaandaar aisa nahin jiski choti uske haath mein na ho. Beshak mera Rubb seedhi raah par hai" },
    { number: 57, arabic: "فَإِن تَوَلَّوْا۟ فَقَدْ أَبْلَغْتُكُم مَّآ أُرْسِلْتُ بِهِۦٓ إِلَيْكُمْ ۚ وَيَسْتَخْلِفُ رَبِّى قَوْمًا غَيْرَكُمْ وَلَا تَضُرُّونَهُۥ شَيْـًٔا ۚ إِنَّ رَبِّى عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌۭ", transliteration: "Fain tawallaw faqad ablaghtukum ma orsiltu bihi ilaykum wayastakhlifu rabbee qawman ghayrakum wala tadurroonahu shayan inna rabbee AAala kulli shayin hafeethun", transliterationB: "Fa in tawallaw faqad ablaghtukum maaa ursiltu biheee ilaikum; wa yastakhlifu Rabbee qawman ghairakum wa laa tadur roonahoo shai'aa; inna Rabbee 'alaa kulli shai'in Hafeez", english: "If ye turn away,- I (at least) have conveyed the Message with which I was sent to you. My Lord will make another people to succeed you, and you will not harm Him in the least. For my Lord hath care and watch over all things", romanUrdu: "Agar tum mooh pherte ho to pher lo, jo paigham de kar main tumhare paas bhejha gaya tha woh main tumko pahuncha chuka hoon. Ab mera Rubb tumhari jagah dusri qaum ko uthayega aur tum uska kuch na bigaad sakoge. Yaqeenan mera Rubb har cheez par nigraan hai.”" },
    { number: 58, arabic: "وَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا هُودًۭا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍۢ مِّنَّا وَنَجَّيْنَٰهُم مِّنْ عَذَابٍ غَلِيظٍۢ", transliteration: "Walamma jaa amruna najjayna hoodan waallatheena amanoo maAAahu birahmatin minna wanajjaynahum min AAathabin ghaleethin", transliterationB: "Wa lammaa jaaa'a amrunaa najainaa Hoodanw wallazeena aamanoo ma'ahoo birahmatim minnaa wa najainaahum min 'azaabin ghaleez", english: "So when Our decree issued, We saved Hud and those who believed with him, by (special) Grace from Ourselves: We saved them from a severe penalty", romanUrdu: "Phir jab hamara hukum aa gaya to humne apni rehmat se Hud ko aur un logon ko jo uske saath iman laye thay nijaat de di aur ek sakht azaab se unhein bacha liya" },
    { number: 59, arabic: "وَتِلْكَ عَادٌۭ ۖ جَحَدُوا۟ بِـَٔايَٰتِ رَبِّهِمْ وَعَصَوْا۟ رُسُلَهُۥ وَٱتَّبَعُوٓا۟ أَمْرَ كُلِّ جَبَّارٍ عَنِيدٍۢ", transliteration: "Watilka AAadun jahadoo biayati rabbihim waAAasaw rusulahu waittabaAAoo amra kulli jabbarin AAaneedin", transliterationB: "Wa tilka 'aad, jahadoo bi Aayaati Rabbihim wa 'asaw Rusulahoo wattaba'ooo amra kulli jabbaarin 'aneed", english: "Such were the 'Ad People: they rejected the Signs of their Lord and Cherisher; disobeyed His messengers; And followed the command of every powerful, obstinate transgressor", romanUrdu: "Yeh hain Aad. Apne Rubb ki aayaat se unhon ne inkar kiya, uske Rasoolon ki baat na maani, aur har jabbar dushman e haqq ki pairwi karte rahey" },
    { number: 60, arabic: "وَأُتْبِعُوا۟ فِى هَٰذِهِ ٱلدُّنْيَا لَعْنَةًۭ وَيَوْمَ ٱلْقِيَٰمَةِ ۗ أَلَآ إِنَّ عَادًۭا كَفَرُوا۟ رَبَّهُمْ ۗ أَلَا بُعْدًۭا لِّعَادٍۢ قَوْمِ هُودٍۢ", transliteration: "WaotbiAAoo fee hathihi alddunya laAAnatan wayawma alqiyamati ala inna AAadan kafaroo rabbahum ala buAAdan liAAadin qawmi hoodin", transliterationB: "Wa utbi'oo fee haazihid dunyaa la'natanw wa Yawmal Qiyaamah; alaaa inna 'Aadan kafaroo Rabbahum; alaa bu'dal li 'Aadin qawmin Hood", english: "And they were pursued by a Curse in this life,- and on the Day of Judgment. Ah! Behold! for the 'Ad rejected their Lord and Cherisher! Ah! Behold! removed (from sight) were 'Ad the people of Hud", romanUrdu: "Aakhir e kaar is duniya mein bhi inpar phitkar padi aur qayamat ke roz bhi. Suno! Aad ne apne Rubb se kufr kiya, Suno! Door phenk diye gaye Aad, Hud ki qaum ke log" },
    { number: 61, arabic: "۞ وَإِلَىٰ ثَمُودَ أَخَاهُمْ صَٰلِحًۭا ۚ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ هُوَ أَنشَأَكُم مِّنَ ٱلْأَرْضِ وَٱسْتَعْمَرَكُمْ فِيهَا فَٱسْتَغْفِرُوهُ ثُمَّ تُوبُوٓا۟ إِلَيْهِ ۚ إِنَّ رَبِّى قَرِيبٌۭ مُّجِيبٌۭ", transliteration: "Waila thamooda akhahum salihan qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu huwa anshaakum mina alardi waistaAAmarakum feeha faistaghfiroohu thumma tooboo ilayhi inna rabbee qareebun mujeebun", transliterationB: "Wa ilaa Samooda akhaahum Saalihaa; qaala yaa qawmi' budul laaha maa lakum min ilaahim ghairuhoo Huwa ansha akum minal ardi wasta' marakum feehaa fastaghfiroohu summa toobooo ilaih; inna Rabbee Qareebum Mujeeb", english: "To the Thamud People (We sent) Salih, one of their own brethren. He said: \"O my people! Worship Allah: ye have no other god but Him. It is He Who hath produced you from the earth and settled you therein: then ask forgiveness of Him, and turn to Him (in repentance): for my Lord is (always) near, ready to answer", romanUrdu: "Aur Samood ki taraf humne unke bhai Saleh ko bheja. Usne kaha, “aey meri qaum ke logon, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai. Wahi hai jisne tumko zameen se paida kiya hai aur yahan tumko basaya hai. Lihaza tum ussey maafi chaho aur uski taraf palat aao. Yaqeenan mera Rubb qareeb hai aur woh duaon ka jawab dene wala hai”" },
    { number: 62, arabic: "قَالُوا۟ يَٰصَٰلِحُ قَدْ كُنتَ فِينَا مَرْجُوًّۭا قَبْلَ هَٰذَآ ۖ أَتَنْهَىٰنَآ أَن نَّعْبُدَ مَا يَعْبُدُ ءَابَآؤُنَا وَإِنَّنَا لَفِى شَكٍّۢ مِّمَّا تَدْعُونَآ إِلَيْهِ مُرِيبٍۢ", transliteration: "Qaloo ya salihu qad kunta feena marjuwwan qabla hatha atanhana an naAAbuda ma yaAAbudu abaona wainnana lafee shakkin mimma tadAAoona ilayhi mureebun", transliterationB: "Qaaloo yaa Saalihu qad kunta feenaa marjuwwan qabla haazaaa atanhaanaaa an na'bu da maa ya'budu aabaaa'unaa wa innanaa lafee shakkim mimmaa tad'oonaaa ilaihi mureeb", english: "They said: \"O Salih! thou hast been of us! a centre of our hopes hitherto! dost thou (now) forbid us the worship of what our fathers worshipped? But we are really in suspicious (disquieting) doubt as to that to which thou invitest us", romanUrdu: "Unhon ne kaha “Aey Saleh, issey pehle tu hamare darmiyan aisa shaks tha jissey badi tawaqquat (expectations) wabasta thi. Kya tum humein in maboodon ki parastish se roakna chahta hai jinki parastish hamare baap dada karte thay? Tu jis tareeqe ki taraf humein bula raha hai iske baarey mein humko sakht shubha(doubt) hai jisne humein khaljaan (disquieting doubt ) mein daal rakkha hai”" },
    { number: 63, arabic: "قَالَ يَٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍۢ مِّن رَّبِّى وَءَاتَىٰنِى مِنْهُ رَحْمَةًۭ فَمَن يَنصُرُنِى مِنَ ٱللَّهِ إِنْ عَصَيْتُهُۥ ۖ فَمَا تَزِيدُونَنِى غَيْرَ تَخْسِيرٍۢ", transliteration: "Qala ya qawmi araaytum in kuntu AAala bayyinatin min rabbee waatanee minhu rahmatan faman yansurunee mina Allahi in AAasaytuhu fama tazeedoonanee ghayra takhseerin", transliterationB: "Qaala yaa qawmi ara'aytum in kuntu 'alaa baiyinatim mir Rabbee wa aataanee minhu rahmatan famai yansurunee minal laahi in 'asaituhoo famaa tazeedoonanee ghaira takhseer", english: "He said: \"O my people! do ye see? if I have a Clear (Sign) from my Lord and He hath sent Mercy unto me from Himself,- who then can help me against Allah if I were to disobey Him? What then would ye add to my (portion) but perdition", romanUrdu: "Saleh ne kaha “ aey biradaraan-e-qaum, tumne kuch is baat par bhi gaur kiya ke agar main apne Rubb ki taraf se ek saaf shahadat rakhta tha, aur phir usne apne rehmat se bhi mujhko nawaz diya to iske baad Allah ki pakad se mujhey kaun bachayega agar main uski nafarmani karoon? Tum mere kis kaam aa sakte ho siway iske ke mujhey aur zyada khasare(nuksan) mein daal do" },
    { number: 64, arabic: "وَيَٰقَوْمِ هَٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمْ ءَايَةًۭ فَذَرُوهَا تَأْكُلْ فِىٓ أَرْضِ ٱللَّهِ وَلَا تَمَسُّوهَا بِسُوٓءٍۢ فَيَأْخُذَكُمْ عَذَابٌۭ قَرِيبٌۭ", transliteration: "Waya qawmi hathihi naqatu Allahi lakum ayatan fatharooha takul fee ardi Allahi wala tamassooha bisooin fayakhuthakum AAathabun qareebun", transliterationB: "Wa yaa qawmi haazihee naaqatul laahi lakum aayatan fazaroohaa taakul feee ardil laahi wa laa tamassoohaa bisooo'in fa yaakhuzakum azaabun qareeb", english: "And O my people! This she-camel of Allah is a symbol to you: leave her to feed on Allah's (free) earth, and inflict no harm on her, or a swift penalty will seize you", romanUrdu: "Aur aey meri qaum ke logon, dekho yeh Allah ki ountni (she-camel) tumhare liye ek nishani hai, isey khuda ki zameen mein charne ke liye azad chodh do. Issey zara taaruz na karna (do not hurt her) warna kuch zyada dair na guzregi ke tumpar khuda ka azaab aa jayega”" },
    { number: 65, arabic: "فَعَقَرُوهَا فَقَالَ تَمَتَّعُوا۟ فِى دَارِكُمْ ثَلَٰثَةَ أَيَّامٍۢ ۖ ذَٰلِكَ وَعْدٌ غَيْرُ مَكْذُوبٍۢ", transliteration: "FaAAaqarooha faqala tamattaAAoo fee darikum thalathata ayyamin thalika waAAdun ghayru makthoobin", transliterationB: "Fa 'aqaroohaa faqaala tamatta'oo fee daarikum salaasata aiyaamin zaalika wa'dun ghairu makzoob", english: "But they did ham-string her. So he said: \"Enjoy yourselves in your homes for three days: (Then will be your ruin): (Behold) there a promise not to be belied", romanUrdu: "Magar unhon ne ountni ko maar dala ispar Saleh ne unko khabardaar kardiya ke “ bas ab teen din apne gharon mein aur reh bas lo. Yeh aisi miyad (promise ) hai jo jhooti na sabit hogi”" },
    { number: 66, arabic: "فَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا صَٰلِحًۭا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍۢ مِّنَّا وَمِنْ خِزْىِ يَوْمِئِذٍ ۗ إِنَّ رَبَّكَ هُوَ ٱلْقَوِىُّ ٱلْعَزِيزُ", transliteration: "Falamma jaa amruna najjayna salihan waallatheena amanoo maAAahu birahmatin minna wamin khizyi yawmiithin inna rabbaka huwa alqawiyyu alAAazeezu", transliterationB: "Falammaa jaaa'a amrunaa najjainaa Saalihanw wal lazeena aamanoo ma'ahoo birahmatim minnaa wa min khizyi Yawmi'iz inna Rabbaka Huwal Qawiyyul 'Azeez", english: "When Our Decree issued, We saved Salih and those who believed with him, by (special) Grace from Ourselves - and from the Ignominy of that day. For thy Lord - He is the Strong One, and able to enforce His Will", romanUrdu: "Aakhir-e-kaar jab hamare faisle ka waqt aa gaya to humne apni rehmat se Saleh ko aur un logon ko jo uske saath iman laye thay bacha liya, aur us din ki ruswayi se unko mehfooz rakkha. Beshak tera Rub hi dar-asal taaqatwar aur bala-dast (All-Mighty) hai" },
    { number: 67, arabic: "وَأَخَذَ ٱلَّذِينَ ظَلَمُوا۟ ٱلصَّيْحَةُ فَأَصْبَحُوا۟ فِى دِيَٰرِهِمْ جَٰثِمِينَ", transliteration: "Waakhatha allatheena thalamoo alssayhatu faasbahoo fee diyarihim jathimeena", transliterationB: "Wa akhazal lazeena zalamus saihatu fa asbahoo fee diyaarihim jaasimeena", english: "The (mighty) Blast overtook the wrong-doers, and they lay prostrate in their homes before the morning", romanUrdu: "Rahey woh log jinhon ne zulm kiya tha to ek sakht dhamake ne unko dhar liya aur woh apni bastiyon mein is tarah be-hiss o harkat (lay lifeless) padey ke padey reh gaye" },
    { number: 68, arabic: "كَأَن لَّمْ يَغْنَوْا۟ فِيهَآ ۗ أَلَآ إِنَّ ثَمُودَا۟ كَفَرُوا۟ رَبَّهُمْ ۗ أَلَا بُعْدًۭا لِّثَمُودَ", transliteration: "Kaan lam yaghnaw feeha ala inna thamooda kafaroo rabbahum ala buAAdan lithamooda", transliterationB: "Ka al lam yaghnaw feehaaa; alaaa inna Samooda kafaroo Rabbahum; alaa bu'dal li Samood", english: "As if they had never dwelt and flourished there. Ah! Behold! for the Thamud rejected their Lord and Cherisher! Ah! Behold! removed (from sight) were the Thamud", romanUrdu: "Ke goya woh wahan kabhi basay hi na thay. Suno! Samood ne apne Rubb se kufr kiya , Suno! Door phenk diye gaye Samood" },
    { number: 69, arabic: "وَلَقَدْ جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوا۟ سَلَٰمًۭا ۖ قَالَ سَلَٰمٌۭ ۖ فَمَا لَبِثَ أَن جَآءَ بِعِجْلٍ حَنِيذٍۢ", transliteration: "Walaqad jaat rusuluna ibraheema bialbushra qaloo salaman qala salamun fama labitha an jaa biAAijlin haneethin", transliterationB: "Wa laqad jaaa'at Rusulunaaa Ibraaheema bilbushraa qaaloo salaaman qaala salaamun famaa labisa an jaaa'a bi'ijin haneez", english: "There came Our messengers to Abraham with glad tidings. They said, \"Peace!\" He answered, \"Peace!\" and hastened to entertain them with a roasted calf", romanUrdu: "Aur dekho, Ibrahim ke paas hamare Farishte khush khabri liye huey pahunche. Kaha tumpar salaam ho, Ibrahim ne jawab diya tumpar bhi salaam ho, phir kuch dair na guzri ke Ibrahim ek bhoona (roasted) hua bachda(calf) (unki ziyafat ke liye) le aaya" },
    { number: 70, arabic: "فَلَمَّا رَءَآ أَيْدِيَهُمْ لَا تَصِلُ إِلَيْهِ نَكِرَهُمْ وَأَوْجَسَ مِنْهُمْ خِيفَةًۭ ۚ قَالُوا۟ لَا تَخَفْ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمِ لُوطٍۢ", transliteration: "Falamma raa aydiyahum la tasilu ilayhi nakirahum waawjasa minhum kheefatan qaloo la takhaf inna orsilna ila qawmi lootin", transliterationB: "Falammaa ra aaa aidiyahum laa tasilu ilaihi nakirahum wa awjasa minhum kheefah; qaaloo la takhaf innaaa ursilnaaa ilaa qawmi Loot", english: "But when he saw their hands went not towards the (meal), he felt some mistrust of them, and conceived a fear of them. They said: \"Fear not: We have been sent against the people of Lut", romanUrdu: "Magar jab dekha ke unke haath khane par nahin badhte to woh unse mushtaba (mistrusted them) ho gaya aur dil mein unse khauf mehsoos karne laga. Unhon ne kaha “daro nahin, hum to Lut ki qaum ki taraf bheje gaye hain”" },
    { number: 71, arabic: "وَٱمْرَأَتُهُۥ قَآئِمَةٌۭ فَضَحِكَتْ فَبَشَّرْنَٰهَا بِإِسْحَٰقَ وَمِن وَرَآءِ إِسْحَٰقَ يَعْقُوبَ", transliteration: "Waimraatuhu qaimatun fadahikat fabashsharnaha biishaqa wamin warai ishaqa yaAAqooba", transliterationB: "Wamra atuhoo qaaa'imatun fadahikat fabashsharnaahaa bi Ishaaqa wa minw waraaa'i Ishaaqa Ya'qoob", english: "And his wife was standing (there), and she laughed: But we gave her glad tidings of Isaac, and after him, of Jacob", romanUrdu: "Ibrahim ki biwi khadi hui thi woh yeh sunkar hass di (laughed) phir humne usko Ishaq ki aur Ishaq ke baad Yaqub ki khushkhabri di" },
    { number: 72, arabic: "قَالَتْ يَٰوَيْلَتَىٰٓ ءَأَلِدُ وَأَنَا۠ عَجُوزٌۭ وَهَٰذَا بَعْلِى شَيْخًا ۖ إِنَّ هَٰذَا لَشَىْءٌ عَجِيبٌۭ", transliteration: "Qalat ya waylata aalidu waana AAajoozun wahatha baAAlee shaykhan inna hatha lashayon AAajeebun", transliterationB: "Qaalat yaa wailataaa 'aalidu wa ana 'ajoozunw wa haaza ba'lee shaikhan inna haazaa lashai'un 'ajeeb", english: "She said: \"Alas for me! shall I bear a child, seeing I am an old woman, and my husband here is an old man? That would indeed be a wonderful thing", romanUrdu: "Woh boli “haye meri kambakhti! Kya ab mere haan aulad hogi jabke main budhiya phoons ho gayi aur yeh mere miyan bhi boodhey ho chuke? Yeh to badi ajeeb baat hai”" },
    { number: 73, arabic: "قَالُوٓا۟ أَتَعْجَبِينَ مِنْ أَمْرِ ٱللَّهِ ۖ رَحْمَتُ ٱللَّهِ وَبَرَكَٰتُهُۥ عَلَيْكُمْ أَهْلَ ٱلْبَيْتِ ۚ إِنَّهُۥ حَمِيدٌۭ مَّجِيدٌۭ", transliteration: "Qaloo ataAAjabeena min amri Allahi rahmatu Allahi wabarakatuhu AAalaykum ahla albayti innahu hameedun majeedun", transliterationB: "Qaalooo ata'jabeena min amril laahi rahmatul laahi wa barakaatuho 'alaikum Ahlal Bayt; innahoo Hameedum Majeed", english: "They said: \"Dost thou wonder at Allah's decree? The grace of Allah and His blessings on you, o ye people of the house! for He is indeed worthy of all praise, full of all glory", romanUrdu: "Farishton ne kaha “Allah ke hukum par taajub karti ho? Ibrahim ke ghar walon, tum logon par to Allah ki rehmat aur uski barkatein hain, aur yaqeenan Allah nihayat qaabil-e-tareef aur badi shaan wala hai”" },
    { number: 74, arabic: "فَلَمَّا ذَهَبَ عَنْ إِبْرَٰهِيمَ ٱلرَّوْعُ وَجَآءَتْهُ ٱلْبُشْرَىٰ يُجَٰدِلُنَا فِى قَوْمِ لُوطٍ", transliteration: "Falamma thahaba AAan ibraheema alrrawAAu wajaathu albushra yujadiluna fee qawmi lootin", transliterationB: "Falammaa zahaba an Ibraaheemar raw'u wa jaaa'at hul bushraaa yujaadilunaa fee qawmi Loot", english: "When fear had passed from (the mind of) Abraham and the glad tidings had reached him, he began to plead with us for Lut's people", romanUrdu: "Phir jab Ibrahim ki ghabrahat door ho gayi aur (aulad ki basharat se) uska dil khush ho gaya to usne qaum e Lut ke maamle mein humse jhagda shuru kiya" },
    { number: 75, arabic: "إِنَّ إِبْرَٰهِيمَ لَحَلِيمٌ أَوَّٰهٌۭ مُّنِيبٌۭ", transliteration: "Inna ibraheema lahaleemun awwahun muneebun", transliterationB: "Inna Ibraaheema lahaleemun awwwaahum muneeb", english: "For Abraham was, without doubt, forbearing (of faults), compassionate, and given to look to Allah", romanUrdu: "Haqeeqat mein Ibrahim bada haleem aur narm dil aadmi tha aur har haal mein hamari taraf rujoo karta tha" },
    { number: 76, arabic: "يَٰٓإِبْرَٰهِيمُ أَعْرِضْ عَنْ هَٰذَآ ۖ إِنَّهُۥ قَدْ جَآءَ أَمْرُ رَبِّكَ ۖ وَإِنَّهُمْ ءَاتِيهِمْ عَذَابٌ غَيْرُ مَرْدُودٍۢ", transliteration: "Ya ibraheemu aAArid AAan hatha innahu qad jaa amru rabbika wainnahum ateehim AAathabun ghayru mardoodin", transliterationB: "Yaaa Ibraaheemu a'rid 'an haazaaa innahoo qad jaaa'a amru Rabbika wa innahum aateehim 'azaabun ghairun mardood", english: "O Abraham! Seek not this. The decree of thy Lord hath gone forth: for them there cometh a penalty that cannot be turned back", romanUrdu: "(Aakhir e kaar hamare Farishton ne ussey kaha) “Aey Ibrahim , issey baaz aa jao, tumhare Rubb ka hukum ho chuka hai aur ab un logon par woh azaab aa kar rahega jo kisi ke phere nahin phir sakta”" },
    { number: 77, arabic: "وَلَمَّا جَآءَتْ رُسُلُنَا لُوطًۭا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًۭا وَقَالَ هَٰذَا يَوْمٌ عَصِيبٌۭ", transliteration: "Walamma jaat rusuluna lootan seea bihim wadaqa bihim tharAAan waqala hatha yawmun AAaseebun", transliterationB: "Wa lammaa jaaa'at Rusulunaa Lootan seee'a bihim wa daaqa bihim zar'anw wa qaala haazaa yawmun 'aseeb", english: "When Our messengers came to Lut, he was grieved on their account and felt himself powerless (to protect) them. He said: \"This is a distressful day", romanUrdu: "Aur jab hamare Farishte Lut ke paas pahunche to unki aamad se woh bahut ghabraya aur dil tangg hua aur kehne laga ke aaj badi museebat ka din hai" },
    { number: 78, arabic: "وَجَآءَهُۥ قَوْمُهُۥ يُهْرَعُونَ إِلَيْهِ وَمِن قَبْلُ كَانُوا۟ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ ۚ قَالَ يَٰقَوْمِ هَٰٓؤُلَآءِ بَنَاتِى هُنَّ أَطْهَرُ لَكُمْ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ فِى ضَيْفِىٓ ۖ أَلَيْسَ مِنكُمْ رَجُلٌۭ رَّشِيدٌۭ", transliteration: "Wajaahu qawmuhu yuhraAAoona ilayhi wamin qablu kanoo yaAAmaloona alssayyiati qala ya qawmi haolai banatee hunna atharu lakum faittaqoo Allaha wala tukhzooni fee dayfee alaysa minkum rajulun rasheedun", transliterationB: "Wa jaaa'ahoo qawmuhoo yuhra'oona ilaihi wa min qablu kaanoo ya'maloonas saiyiaat; qaala yaa qawmi haaa'ulaaa'i banaatee hunna atharu lakum fattaqul laaha wa laa tukhzooni fee daifee alaisa minkum rajulur rasheed", english: "And his people came rushing towards him, and they had been long in the habit of practising abominations. He said: \"O my people! Here are my daughters: they are purer for you (if ye marry)! Now fear Allah, and cover me not with shame about my guests! Is there not among you a single right-minded man", romanUrdu: "(In mehmaano ka aana tha ke) uski qaum ke log bay-ikhtiyar uske ghar ki taraf daud padey. Pehle se woh aisi hi badkariyon ke khugar thay. Lut ne unse kaha “bhaiyon, yeh meri betiyan maujood hain, yeh tumhare liye pakeeza-tarr hain. Kuch khuda ka khauf karo aur mere mehmano ke mamle mein mujhey zaleel na karo. Kya tum mein koi bhala aadmi nahin?”" },
    { number: 79, arabic: "قَالُوا۟ لَقَدْ عَلِمْتَ مَا لَنَا فِى بَنَاتِكَ مِنْ حَقٍّۢ وَإِنَّكَ لَتَعْلَمُ مَا نُرِيدُ", transliteration: "Qaloo laqad AAalimta ma lana fee banatika min haqqin wainnaka lataAAlamu ma nureedu", transliterationB: "Qaaloo laqad 'alimta maa lanaa fee banastika min haqq, wa innaka lata'lamu maa nureed", english: "They said: \"Well dost thou know we have no need of thy daughters: indeed thou knowest quite well what we want", romanUrdu: "Unhon ne jawab diya “tujhey to maloom hi hai ke teri betiyon mein hamara koi hissa nahin hai aur tu yeh bhi jaanta hai ke hum chahte kya hain”" },
    { number: 80, arabic: "قَالَ لَوْ أَنَّ لِى بِكُمْ قُوَّةً أَوْ ءَاوِىٓ إِلَىٰ رُكْنٍۢ شَدِيدٍۢ", transliteration: "Qala law anna lee bikum quwwatan aw awee ila ruknin shadeedin", transliterationB: "Qaala law anna lee bikum quwwatan aw aaweee ilaa ruknin shadeed", english: "He said: \"Would that I had power to suppress you or that I could betake myself to some powerful support", romanUrdu: "Lut ne kaha “ kaash mere paas itni taaqat hoti ke tumhein seedha kardeta, ya koi mazboot sahara hi hota ke uski panaah leta”" },
    { number: 81, arabic: "قَالُوا۟ يَٰلُوطُ إِنَّا رُسُلُ رَبِّكَ لَن يَصِلُوٓا۟ إِلَيْكَ ۖ فَأَسْرِ بِأَهْلِكَ بِقِطْعٍۢ مِّنَ ٱلَّيْلِ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌ إِلَّا ٱمْرَأَتَكَ ۖ إِنَّهُۥ مُصِيبُهَا مَآ أَصَابَهُمْ ۚ إِنَّ مَوْعِدَهُمُ ٱلصُّبْحُ ۚ أَلَيْسَ ٱلصُّبْحُ بِقَرِيبٍۢ", transliteration: "Qaloo ya lootu inna rusulu rabbika lan yasiloo ilayka faasri biahlika biqitAAin mina allayli wala yaltafit minkum ahadun illa imraataka innahu museebuha ma asabahum inna mawAAidahumu alssubhu alaysa alssubhu biqareebin", transliterationB: "Qaaloo yaa Lootu innaa Rusulu Rabbika lai yasiloo ilaika fa asri bi ahlika biqit 'im minal laili wa laa yaltafit minkum ahadun illam ra ataka innahoo museebuhaa maaa asaabahum; inna maw'i dahumus subh; alaisas subhu biqareeb", english: "(The Messengers) said: \"O Lut! We are Messengers from thy Lord! By no means shall they reach thee! now travel with thy family while yet a part of the night remains, and let not any of you look back: but thy wife (will remain behind): To her will happen what happens to the people. Morning is their time appointed: Is not the morning nigh", romanUrdu: "Tab Farishton ne ussey kaha ke “aey Lut, hum tere Rubb ke bheje huye Farishtey hain. Yeh log tera kuch na bigad sakenge. Bas tu kuch raat rahey apne ehal o ayal ko lekar nikal jaa aur dekho, tum mein se koi shaks peechey palat kar na dekhey magar teri biwi (saath nahin jayegi) kyunke uspar bhi wahi kuch guzarne wala hai jo in logon par guzarna hai. Unki tabahi ke liye subah ka waqt muqarrar hai. Subah hotey ab dair hi kitni hai”" },
    { number: 82, arabic: "فَلَمَّا جَآءَ أَمْرُنَا جَعَلْنَا عَٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهَا حِجَارَةًۭ مِّن سِجِّيلٍۢ مَّنضُودٍۢ", transliteration: "Falamma jaa amruna jaAAalna AAaliyaha safilaha waamtarna AAalayha hijaratan min sijjeelin mandoodin", transliterationB: "Falammaa jaaa'a amrunaa ja'alnaa 'aaliyahaa saafilahaa wa amtamaa 'alaihaa hijaaratam min sijjeelim mandood", english: "When Our Decree issued, We turned (the cities) upside down, and rained down on them brimstones hard as baked clay, spread, layer on layer", romanUrdu: "Phir jab hamare faisle ka waqt aa pahuncha to humne us basti ko talpat (upside down) kardiya aur uspar paki hui mitti (baked clay) ke patthar tabad-tod barsaye" },
    { number: 83, arabic: "مُّسَوَّمَةً عِندَ رَبِّكَ ۖ وَمَا هِىَ مِنَ ٱلظَّٰلِمِينَ بِبَعِيدٍۢ", transliteration: "Musawwamatan AAinda rabbika wama hiya mina alththalimeena bibaAAeedin", transliterationB: "Musawwamatan 'inda Rabbik; wa maa hiya minaz zaalimena biba'eed", english: "Marked as from thy Lord: Nor are they ever far from those who do wrong", romanUrdu: "Jin mein se har patthar tere Rubb ke haan nishaan zadah tha aur zalimon se yeh saza kuch door nahin hai" },
    { number: 84, arabic: "۞ وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا ۚ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ وَلَا تَنقُصُوا۟ ٱلْمِكْيَالَ وَٱلْمِيزَانَ ۚ إِنِّىٓ أَرَىٰكُم بِخَيْرٍۢ وَإِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍۢ مُّحِيطٍۢ", transliteration: "Waila madyana akhahum shuAAayban qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu wala tanqusoo almikyala waalmeezana innee arakum bikhayrin wainnee akhafu AAalaykum AAathaba yawmin muheetin", transliterationB: "Wa ilaa Madyana akhaahum Shu'aibaa; qaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuhoo wa laa tanqusul mikyaala walmeezaan; inneee araakum bikhairinw wa innee akhaafu 'alaikum 'azaaba Yawmim muheet", english: "To the Madyan People (We sent) Shu'aib, one of their own brethren: he said: \"O my people! worship Allah: Ye have no other god but Him. And give not short measure or weight: I see you in prosperity, but I fear for you the penalty of a day that will compass (you) all round", romanUrdu: "Aur Madiyan walon ki taraf humne unke bhai Shoaib ko bheja. Usne kaha “aey meri qaum ke logon, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai. Aur naap toal mein kami na kiya karo. Aaj main tumko acchey haal mein dekh raha hoon, magar mujhey darr hai ke kal tumpar aisa din aayega jiska azaab sabko gher lega" },
    { number: 85, arabic: "وَيَٰقَوْمِ أَوْفُوا۟ ٱلْمِكْيَالَ وَٱلْمِيزَانَ بِٱلْقِسْطِ ۖ وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", transliteration: "Waya qawmi awfoo almikyala waalmeezana bialqisti wala tabkhasoo alnnasa ashyaahum wala taAAthaw fee alardi mufsideena", transliterationB: "Wa yaa qawmi awful mikyaala walmeezaana bilqisti wa laa tabkhasun naasa ashyaaa'ahum wa laa ta'saw fil ardi mufsideen", english: "And O my people! give just measure and weight, nor withhold from the people the things that are their due: commit not evil in the land with intent to do mischief", romanUrdu: "Aur aey biradraan e quam, theek theek insaf ke saath pura naapo aur tolo (measure) aur logon ko unki cheezon mein ghata (loss) na diya karo aur zameen mein fasaad na phaylate phiro" },
    { number: 86, arabic: "بَقِيَّتُ ٱللَّهِ خَيْرٌۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ ۚ وَمَآ أَنَا۠ عَلَيْكُم بِحَفِيظٍۢ", transliteration: "Baqiyyatu Allahi khayrun lakum in kuntum mumineena wama ana AAalaykum bihafeethin", transliterationB: "Baqiyyatul laahi khairul lakum in kuntum mu'mineen; wa maa ana 'alaikum bihafeez", english: "That which is left you by Allah is best for you, if ye (but) believed! but I am not set over you to keep watch", romanUrdu: "Allah ki di hui bachat (gains) tumhare liye betar hai agar tum momin ho aur bahar-haal main tumhare upar koi nigraan e kaar nahin hoon”" },
    { number: 87, arabic: "قَالُوا۟ يَٰشُعَيْبُ أَصَلَوٰتُكَ تَأْمُرُكَ أَن نَّتْرُكَ مَا يَعْبُدُ ءَابَآؤُنَآ أَوْ أَن نَّفْعَلَ فِىٓ أَمْوَٰلِنَا مَا نَشَٰٓؤُا۟ ۖ إِنَّكَ لَأَنتَ ٱلْحَلِيمُ ٱلرَّشِيدُ", transliteration: "Qaloo ya shuAAaybu asalatuka tamuruka an natruka ma yaAAbudu abaona aw an nafAAala fee amwalina ma nashao innaka laanta alhaleemu alrrasheedu", transliterationB: "Qaaloo yaa Shu'aybu asalaatuka taamuruka an natruka maa ya'budu aabaaa'unaaa aw an naf'ala feee amwaalinaa maa nashaaa'oo innaka la antal haleemur rasheed", english: "They said: \"O Shu'aib! Does thy (religion of) prayer command thee that we leave off the worship which our fathers practised, or that we leave off doing what we like with our property? truly, thou art the one that forbeareth with faults and is right-minded", romanUrdu: "Unhon ne jawab diya “aey shoaib, kya teri namaz tujhey yeh sikhati hai ke hum un sarey maboodon ko chodh dein jinki parastish hamare baap dada karte thay? Ya yeh ke humko apne maal mein apne mansha(as we please) ke mutabiq tasrruf(spend/use) karne ka ikhtiyar na ho? Bas tu hi to ek aali zarf aur raastbaaz aadmi ( forbearing and right-directed) reh gaya hai”" },
    { number: 88, arabic: "قَالَ يَٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍۢ مِّن رَّبِّى وَرَزَقَنِى مِنْهُ رِزْقًا حَسَنًۭا ۚ وَمَآ أُرِيدُ أَنْ أُخَالِفَكُمْ إِلَىٰ مَآ أَنْهَىٰكُمْ عَنْهُ ۚ إِنْ أُرِيدُ إِلَّا ٱلْإِصْلَٰحَ مَا ٱسْتَطَعْتُ ۚ وَمَا تَوْفِيقِىٓ إِلَّا بِٱللَّهِ ۚ عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ أُنِيبُ", transliteration: "Qala ya qawmi araaytum in kuntu AAala bayyinatin min rabbee warazaqanee minhu rizqan hasanan wama oreedu an okhalifakum ila ma anhakum AAanhu in oreedu illa alislaha ma istataAAtu wama tawfeeqee illa biAllahi AAalayhi tawakkaltu wailayhi oneebu", transliterationB: "Qaala yaa qawmi ara'aitum in kuntu 'alaa baiyinatim mir Rabbee wa razaqanee minhu rizqan hasanaa; wa maaa ureedu an ukhaalifakum ilaa maaa anhaakum 'anh; in ureedu illal islaaha mastata't; wa maa tawfeeqeee illaa billaah; 'alaihi tawakkaltu wa ilaihi uneeb", english: "He said: \"O my people! see ye whether I have a Clear (Sign) from my Lord, and He hath given me sustenance (pure and) good as from Himself? I wish not, in opposition to you, to do that which I forbid you to do. I only desire (your) betterment to the best of my power; and my success (in my task) can only come from Allah. In Him I trust, and unto Him I look", romanUrdu: "Shoaib ne kaha “bhaiyon, tum khud hi socho ke agar main apne Rubb ki taraf se ek khuli shahadat par tha aur phir usne apne haan se mujhko accha rizq bhi ata kiya (to iske baad main tumhari gumraahiyon aur haraam-khoriyon mein tumhara shareek e haal kaise ho sakta hoon?) Aur main hargiz yeh nahin chahta ke jin baaton se main tumko roakta hoon unka khud irteqab karoon. Main to islaah karna chahta hoon jahan tak bhi mera bas chale aur yeh jo kuch main karna chachta hoon uska saara inhisaar Allah ki taufeeq par hai. Usi par maine bharosa kiya aur har maamle mein usi ki taraf main rujoo karta hoon" },
    { number: 89, arabic: "وَيَٰقَوْمِ لَا يَجْرِمَنَّكُمْ شِقَاقِىٓ أَن يُصِيبَكُم مِّثْلُ مَآ أَصَابَ قَوْمَ نُوحٍ أَوْ قَوْمَ هُودٍ أَوْ قَوْمَ صَٰلِحٍۢ ۚ وَمَا قَوْمُ لُوطٍۢ مِّنكُم بِبَعِيدٍۢ", transliteration: "Waya qawmi la yajrimannakum shiqaqee an yuseebakum mithlu ma asaba qawma noohin aw qawma hoodin aw qawma salihin wama qawmu lootin minkum bibaAAeedin", transliterationB: "Wa yaa qawmi laa yajri mannakum shiqaaqeee ai yuseebakum mislu maaa asaaba qawma Noohin aw qawma Hoodin aw qawma Saalih; wa maa qawmu Lootim minkum biba'eed", english: "And O my people! let not my dissent (from you) cause you to sin, lest ye suffer a fate similar to that of the people of Noah or of Hud or of Salih, nor are the people of Lut far off from you", romanUrdu: "Aur aey biradraan e qaum, mere khilaf tumhari hadd dharmi kahin yeh naubat na pahuncha de ke aakhir e kaar tumpar bhi wahi azaab aa kar rahey jo Nooh ya Hood ya Saleh ki qaum par aaya tha. Aur Lut ki qaum to tumse kuch zyada door bhi nahin hai" },
    { number: 90, arabic: "وَٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ ۚ إِنَّ رَبِّى رَحِيمٌۭ وَدُودٌۭ", transliteration: "Waistaghfiroo rabbakum thumma tooboo ilayhi inna rabbee raheemun wadoodun", transliterationB: "Wastaghfiroo Rabbakum summa toobooo ilaih; inna Rabbee Raheemunw Wadood", english: "But ask forgiveness of your Lord, and turn unto Him (in repentance): For my Lord is indeed full of mercy and loving-kindness", romanUrdu: "Dekho! Apne Rubb se maafi maango aur uski taraf palat aao, beshak mera Rubb raheem hai aur apni makhlooq se muhabbat rakhta hai”" },
    { number: 91, arabic: "قَالُوا۟ يَٰشُعَيْبُ مَا نَفْقَهُ كَثِيرًۭا مِّمَّا تَقُولُ وَإِنَّا لَنَرَىٰكَ فِينَا ضَعِيفًۭا ۖ وَلَوْلَا رَهْطُكَ لَرَجَمْنَٰكَ ۖ وَمَآ أَنتَ عَلَيْنَا بِعَزِيزٍۢ", transliteration: "Qaloo ya shuAAaybu ma nafqahu katheeran mimma taqoolu wainna lanaraka feena daAAeefan walawla rahtuka larajamnaka wama anta AAalayna biAAazeezin", transliterationB: "Qaaloo yaa Shu'aibu maa nafqahu kaseeram mimmaa taqoolu wa innaa lanaraaka feenaa da'eefanw wa law laa rahtuka larajamnaaka wa maaa anta 'alainaa bi'azeez", english: "They said: \"O Shu'aib! much of what thou sayest we do not understand! In fact among us we see that thou hast no strength! Were it not for thy family, we should certainly have stoned thee! for thou hast among us no great position", romanUrdu: "Unhon ne jawab diya “aey shoaib, teri bahut si baatein to hamari samajh hi mein nahin aati. Aur hum dekhte hain ke tu hamare darmiyan ek be-zoar aadmi hai. Teri biradari na hoti to hum kabhi ka tujhey sangsaar (stone to death) kar chuke hotey, tera balboota to itna nahin hai ke humpar bhari ho”" },
    { number: 92, arabic: "قَالَ يَٰقَوْمِ أَرَهْطِىٓ أَعَزُّ عَلَيْكُم مِّنَ ٱللَّهِ وَٱتَّخَذْتُمُوهُ وَرَآءَكُمْ ظِهْرِيًّا ۖ إِنَّ رَبِّى بِمَا تَعْمَلُونَ مُحِيطٌۭ", transliteration: "Qala ya qawmi arahtee aAAazzu AAalaykum mina Allahi waittakhathtumoohu waraakum thihriyyan inna rabbee bima taAAmaloona muheetun", transliterationB: "Qaala yaa qawmi arahteee a'azzu 'alaikum minal laahi wattakhaztumoohu waraaa'akum zihriyyan inna Rabbee bimaa ta'maloona muheet", english: "He said: \"O my people! is then my family of more consideration with you than Allah? For ye cast Him away behind your backs (with contempt). But verily my Lord encompasseth on all sides all that ye do", romanUrdu: "Shoaib ne kaha “bhaiyon, kya meri biradri tumpar Allah se zyada bhari hai ke tumne (biradri ka to khauf kiya aur) Allah ko bilkul pas e pusht (behind your back) daal diya? Jaan rakkho ke jo kuch tum kar rahey ho woh Allah ki giraft se bahar nahin hai" },
    { number: 93, arabic: "وَيَٰقَوْمِ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنِّى عَٰمِلٌۭ ۖ سَوْفَ تَعْلَمُونَ مَن يَأْتِيهِ عَذَابٌۭ يُخْزِيهِ وَمَنْ هُوَ كَٰذِبٌۭ ۖ وَٱرْتَقِبُوٓا۟ إِنِّى مَعَكُمْ رَقِيبٌۭ", transliteration: "Waya qawmi iAAmaloo AAala makanatikum innee AAamilun sawfa taAAlamoona man yateehi AAathabun yukhzeehi waman huwa kathibun wairtaqiboo inne maAAakum raqeebun", transliterationB: "Wa yaa qawmi' maloo 'alaa makaanatikum innee 'aamilun sawfa ta'lamoona mai yaateehi 'azaabuny yukhzeehi wa man huwa kaazib; wartaqibooo innnee ma'akum raqeeb", english: "And O my people! Do whatever ye can: I will do (my part): Soon will ye know who it is on whom descends the penalty of ignominy; and who is a liar! and watch ye! for I too am watching with you", romanUrdu: "Aey meri qaum ke logon, tum apne tareeqe par kaam kiye jao aur main apne tareeqe par karta rahoonga. Jaldi hi tumhein maloom ho jayega ke kis par zillat ka azaab aata hai aur kaun jhoota hai. Tum bhi intezaar karo aur main bhi tumhare saath chasm-bara hoon (I shall also watch with you)”" },
    { number: 94, arabic: "وَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا شُعَيْبًۭا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍۢ مِّنَّا وَأَخَذَتِ ٱلَّذِينَ ظَلَمُوا۟ ٱلصَّيْحَةُ فَأَصْبَحُوا۟ فِى دِيَٰرِهِمْ جَٰثِمِينَ", transliteration: "Walamma jaa amruna najjayna shuAAayban waallatheena amanoo maAAahu birahmatin minna waakhathati allatheena thalamoo alssayhatu faasbahoo fee diyarihim jathimeena", transliterationB: "Wa lammaa jaaa'a amrunaa najjainaa shu'aibanw wal lazeena aamanoo ma'ahoo birahmatim minnaa wa akhazatil lazeena zalamus saihatu fa asbahoo fee diyaarihim jaasimeen", english: "When Our decree issued, We saved Shu'aib and those who believed with him, by (special) mercy from Ourselves: But the (mighty) blast did seize the wrong-doers, and they lay prostrate in their homes by the morning", romanUrdu: "Aakhir e kaar jab hamare faisle ka waqt aa gaya to humne apni rehmat se shoaib aur uske saathi momino ko bacha liya aur jin logon ne zulm kiya tha unko ek sakht dhamake ne aisa pakda ke woh apni bastiyon mein bay-hiss o harkat (lay lifeless) padey ke padey reh gaye" },
    { number: 95, arabic: "كَأَن لَّمْ يَغْنَوْا۟ فِيهَآ ۗ أَلَا بُعْدًۭا لِّمَدْيَنَ كَمَا بَعِدَتْ ثَمُودُ", transliteration: "Kaan lam yaghnaw feeha ala buAAdan limadyana kama baAAidat thamoodu", transliterationB: "Ka-al-lam yaghnaw feehaaa; alaa bu'dal li Madyana Kamaa ba'idat Samood", english: "As if they had never dwelt and flourished there! Ah! Behold! How the Madyan were removed (from sight) as were removed the Thamud", romanUrdu: "Goya woh kabhi wahan rahey basey hi na thay. Suno! Madiyan waley bhi door phenk diye gaye jis tarah Samood phenke gaye thay" },
    { number: 96, arabic: "وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَٰتِنَا وَسُلْطَٰنٍۢ مُّبِينٍ", transliteration: "Walaqad arsalna moosa biayatina wasultanin mubeenin", transliterationB: "Wa laqad arsalnaa Moosaa bi Aayaatinaa wa sultaanim mubeen", english: "And we sent Moses, with Our Clear (Signs) and an authority manifest", romanUrdu: "Aur Moosa ko humne apni nishaniyon aur khuli khuli sanad e mamoriyat (clear authority) ke saath Firoun aur uske ayan e sultanat ki taraf bheja" },
    { number: 97, arabic: "إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱتَّبَعُوٓا۟ أَمْرَ فِرْعَوْنَ ۖ وَمَآ أَمْرُ فِرْعَوْنَ بِرَشِيدٍۢ", transliteration: "Ila firAAawna wamalaihi faittabaAAoo amra firAAawna wama amru firAAawna birasheedin", transliterationB: "Ilaa Fir'awna wa mala'ihee fattaba'ooo amra Fir'awna wa maaa amru Fir'awna birasheed", english: "Unto Pharaoh and his chiefs: but they followed the command of Pharaoh and the command of Pharaoh was no right (guide)", romanUrdu: "Magar unhon ne Firoun ke hukum ki pairwi ki halanke Firoun ka hukum raasti (right-direction) par na tha" },
    { number: 98, arabic: "يَقْدُمُ قَوْمَهُۥ يَوْمَ ٱلْقِيَٰمَةِ فَأَوْرَدَهُمُ ٱلنَّارَ ۖ وَبِئْسَ ٱلْوِرْدُ ٱلْمَوْرُودُ", transliteration: "Yaqdumu qawmahu yawma alqiyamati faawradahumu alnnara wabisa alwirdu almawroodu", transliterationB: "Yaqdumu qawmahoo Yawmal Qiyaamati fa awrada humun Naara wa bi'sal wirdul mawrood", english: "He will go before his people on the Day of Judgment, and lead them into the Fire (as cattle are led to water): But woeful indeed will be the place to which they are led", romanUrdu: "Qayamat ke roz woh apni qaum ke aagey aagey hoga aur apni peshwayi mein unhein dozakh ki taraf le jayega. Kaisi badhtar jaye wurood (wretched destination) hai yeh jis par koi pahunche" },
    { number: 99, arabic: "وَأُتْبِعُوا۟ فِى هَٰذِهِۦ لَعْنَةًۭ وَيَوْمَ ٱلْقِيَٰمَةِ ۚ بِئْسَ ٱلرِّفْدُ ٱلْمَرْفُودُ", transliteration: "WaotbiAAoo fee hathihi laAAnatan wayawma alqiyamati bisa alrrifdu almarfoodu", transliterationB: "Wa utbi'oo fee haazihee la'natanw wa Yawmal Qiyaamah; bi'sar rifdul marfood", english: "And they are followed by a curse in this (life) and on the Day of Judgment: and woeful is the gift which shall be given (unto them)", romanUrdu: "Aur un logon par duniya mein bhi laanat padi aur qayamat ke roz bhi padeygi. Kaisa bura sila hai yeh jo kisi ko miley" },
    { number: 100, arabic: "ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْقُرَىٰ نَقُصُّهُۥ عَلَيْكَ ۖ مِنْهَا قَآئِمٌۭ وَحَصِيدٌۭ", transliteration: "Thalika min anbai alqura naqussuhu AAalayka minha qaimun wahaseedun", transliterationB: "Zaalika min ambaaa'il quraa naqussuhoo 'alaika minhaa qaaa'imunw wa haseed", english: "These are some of the stories of communities which We relate unto thee: of them some are standing, and some have been mown down (by the sickle of time)", romanUrdu: "Yeh chand bastiyaon ki sarguzisht (account) hai jo hum tumhein suna rahey hain. Inmein se baaz ab bhi khadi hain aur baaz ki fasal kat chuki hai" },
    { number: 101, arabic: "وَمَا ظَلَمْنَٰهُمْ وَلَٰكِن ظَلَمُوٓا۟ أَنفُسَهُمْ ۖ فَمَآ أَغْنَتْ عَنْهُمْ ءَالِهَتُهُمُ ٱلَّتِى يَدْعُونَ مِن دُونِ ٱللَّهِ مِن شَىْءٍۢ لَّمَّا جَآءَ أَمْرُ رَبِّكَ ۖ وَمَا زَادُوهُمْ غَيْرَ تَتْبِيبٍۢ", transliteration: "Wama thalamnahum walakin thalamoo anfusahum fama aghnat AAanhum alihatuhumu allatee yadAAoona min dooni Allahi min shayin lamma jaa amru rabbika wama zadoohum ghayra tatbeebin", transliterationB: "Wa maa zalamnaahum wa laakin zalamooo anfusahum famaaa aghnat 'anhum aalihatuhumul latee yad'oona min doonil laahi min shai'il lammaa jaaa'a amru Rabbika wa maa zaadoohum ghaira tatbeeb", english: "It was not We that wronged them: They wronged their own souls: the deities, other than Allah, whom they invoked, profited them no whit when there issued the decree of thy Lord: Nor did they add aught (to their lot) but perdition", romanUrdu: "Humne unpar zulm nahin kiya, unhon ne aap hi apne upar sitam dhaya. Aur jab Allah ka hukum aa gaya to unke woh mabood jinhein woh Allah ko chodh kar pukara karte thay unke kuch kaam na aa sakey. Aur unhon ne halakat o barbadi ke siwa unhein kuch faiyda na diya" },
    { number: 102, arabic: "وَكَذَٰلِكَ أَخْذُ رَبِّكَ إِذَآ أَخَذَ ٱلْقُرَىٰ وَهِىَ ظَٰلِمَةٌ ۚ إِنَّ أَخْذَهُۥٓ أَلِيمٌۭ شَدِيدٌ", transliteration: "Wakathalika akhthu rabbika itha akhatha alqura wahiya thalimatun inna akhthahu aleemun shadeedun", transliterationB: "Wa kazaalika akhzu Rabbika izaaa akhazal quraa wa hiya zaalimah; inna akhzahooo aleemun shadeed", english: "Such is the chastisement of thy Lord when He chastises communities in the midst of their wrong: grievous, indeed, and severe is His chastisement", romanUrdu: "Aur tera Rubb jab kisi zalim basti ko pakadta hai to phir uski pakad aisi hi hua karti hai, fil waqeh uski pakad badi sakht aur dardnaak hoti hai" },
    { number: 103, arabic: "إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّمَنْ خَافَ عَذَابَ ٱلْءَاخِرَةِ ۚ ذَٰلِكَ يَوْمٌۭ مَّجْمُوعٌۭ لَّهُ ٱلنَّاسُ وَذَٰلِكَ يَوْمٌۭ مَّشْهُودٌۭ", transliteration: "Inna fee thalika laayatan liman khafa AAathaba alakhirati thalika yawmun majmooAAun lahu alnnasu wathalika yawmun mashhoodun", transliterationB: "Inna fee zaalika la aayatal liman khaafa 'azaabal Aakhirah; zaalika Yawmum majmoo'ul lahun naasu wa zaalika Yawmum mashhood", english: "In that is a Sign for those who fear the penalty of the Hereafter: that is a Day for which mankind will be gathered together: that will be a Day of Testimony", romanUrdu: "Haqeeqat yeh hai ke is mein ek nishani hai har us shaks ke liye jo azaab e aakhirat ka khauf karey. Woh ek din hoga jismein sab log jamaa hongey aur phir jo kuch bhi us roz hoga sab ki aankhon ke saamne hoga" },
    { number: 104, arabic: "وَمَا نُؤَخِّرُهُۥٓ إِلَّا لِأَجَلٍۢ مَّعْدُودٍۢ", transliteration: "Wama nuakhkhiruhu illa liajalin maAAdoodin", transliterationB: "Wa maa nu'akhkhiruhooo illaa li ajalim ma'dood", english: "Nor shall We delay it but for a term appointed", romanUrdu: "Hum uske laney mein kuch bahut zyada takheer nahin kar rahey hain, bas ek gini chuni muddat uske liye muqarrar hai" },
    { number: 105, arabic: "يَوْمَ يَأْتِ لَا تَكَلَّمُ نَفْسٌ إِلَّا بِإِذْنِهِۦ ۚ فَمِنْهُمْ شَقِىٌّۭ وَسَعِيدٌۭ", transliteration: "Yawma yati la takallamu nafsun illa biithnihi faminhum shaqiyyun wasaAAeedin", transliterationB: "Yawma yaati laa takallamu nafsun illaa bi iznih; faminhum shaqiyyunw wa sa'eed", english: "The day it arrives, no soul shall speak except by His leave: of those (gathered) some will be wretched and some will be blessed", romanUrdu: "Jab woh aayega to kisi ko baat karne ki majal na hogi, illa yeh ke khuda ki ijazat se kuch arz karey, phir kuch log us roz badbakht hongey aur kuch neik bakht" },
    { number: 106, arabic: "فَأَمَّا ٱلَّذِينَ شَقُوا۟ فَفِى ٱلنَّارِ لَهُمْ فِيهَا زَفِيرٌۭ وَشَهِيقٌ", transliteration: "Faamma allatheena shaqoo fafee alnnari lahum feeha zafeerun washaheequn", transliterationB: "Fa ammal lazeena shaqoo fafin Naari lahum feehaa zafeerunw wa shaheeq", english: "Those who are wretched shall be in the Fire: There will be for them therein (nothing but) the heaving of sighs and sobs", romanUrdu: "Jo bad-bakht hongey woh dozakh mein jayenge (jahan garmi aur pyas ki shiddat se). Woh hanpenge aur phunkare marenge (sigh and groan)" },
    { number: 107, arabic: "خَٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ إِلَّا مَا شَآءَ رَبُّكَ ۚ إِنَّ رَبَّكَ فَعَّالٌۭ لِّمَا يُرِيدُ", transliteration: "Khalideena feeha ma damati alssamawatu waalardu illa ma shaa rabbuka inna rabbaka faAAAAalun lima yureedu", transliterationB: "Khaalideena feehaa maa daamatis samaawaatu wal ardu illaa maa shaaa'a Rabbuk; inna Rabbaka fa' 'aalul limaa yureed", english: "They will dwell therein for all the time that the heavens and the earth endure, except as thy Lord willeth: for thy Lord is the (sure) accomplisher of what He planneth", romanUrdu: "Aur usi halat mein woh hamesha rahenge jab tak ke zameen o aasman qayam hain, illa yeh ke tera Rubb kuch aur chahe. Beshak tera Rubb poora ikhtiyar rakhta hai ke jo chahe karey" },
    { number: 108, arabic: "۞ وَأَمَّا ٱلَّذِينَ سُعِدُوا۟ فَفِى ٱلْجَنَّةِ خَٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَٰوَٰتُ وَٱلْأَرْضُ إِلَّا مَا شَآءَ رَبُّكَ ۖ عَطَآءً غَيْرَ مَجْذُوذٍۢ", transliteration: "Waamma allatheena suAAidoo fafee aljannati khalideena feeha ma damati alssamawatu waalardu illa ma shaa rabbuka AAataan ghayra majthoothin", transliterationB: "Wa ammal lazeena su'idoo fafil Jannati khaalideena feehaa maa daamatis samaawaatu wal ardu illaa maa shaaa'a Rabbuk; ataaa'an ghaira majzooz", english: "And those who are blessed shall be in the Garden: They will dwell therein for all the time that the heavens and the earth endure, except as thy Lord willeth: a gift without break", romanUrdu: "Rahey woh log jo neik bakht niklenge , to woh jannat mein jayenge aur wahan hamesha rahenge jab tak zameen o aasman qayam hain, illa yeh ke tera Rubb kuch aur chache. Aisi bakshish unko milegi jiska silsila kabhi munqata (khatam) na hoga" },
    { number: 109, arabic: "فَلَا تَكُ فِى مِرْيَةٍۢ مِّمَّا يَعْبُدُ هَٰٓؤُلَآءِ ۚ مَا يَعْبُدُونَ إِلَّا كَمَا يَعْبُدُ ءَابَآؤُهُم مِّن قَبْلُ ۚ وَإِنَّا لَمُوَفُّوهُمْ نَصِيبَهُمْ غَيْرَ مَنقُوصٍۢ", transliteration: "Fala taku fee miryatin mimma yaAAbudu haolai ma yaAAbudoona illa kama yaAAbudu abaohum min qablu wainna lamuwaffoohum naseebahum ghayra manqoosin", transliterationB: "Falaa taku fee miryatim mimmmaa ya'budu haaa'ulaaa'; maa ya'budoona illaa kamaa ya'budu aabaaa'uhum min qabl; wa innaa lamuwaf foohum naseebahum ghaira manqoos", english: "Be not then in doubt as to what these men worship. They worship nothing but what their fathers worshipped before (them): but verily We shall pay them back (in full) their portion without (the least) abatement", romanUrdu: "Pas (aey Nabi ), tu un maboodon ki taraf se kisi shakk mein na reh jinki yeh log ibadat kar rahey hain. Yeh to (bas lakeer ke fakeer baney huye) usi tarah pooja paat kiye ja rahey hain jis tarah pehle unke baap dada karte thay. Aur hum inka hissa inhein bharpur denge bagair iske ke is mein kuch kaat kasar ho" },
    { number: 110, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَٰبَ فَٱخْتُلِفَ فِيهِ ۚ وَلَوْلَا كَلِمَةٌۭ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ ۚ وَإِنَّهُمْ لَفِى شَكٍّۢ مِّنْهُ مُرِيبٍۢ", transliteration: "Walaqad atayna moosa alkitaba faikhtulifa feehi walawla kalimatun sabaqat min rabbika laqudiya baynahum wainnahum lafee shakkin minhu mureebun", transliterationB: "Wa laqad aatainaa Moosal Kitaaba fakhtulifa feeh; wa law laa Kalimatun sabaqat mir Rabbika laqudiya bainahum; wa innahum lafee shakkim minhu mureeb", english: "We certainly gave the Book to Moses, but differences arose therein: had it not been that a word had gone forth before from thy Lord, the matter would have been decided between them, but they are in suspicious doubt concerning it", romanUrdu: "Hum issey pehle Moosa ko bhi kitaab de chuke hain aur uske barey mein bhi ikhtilaf kiya gaya tha (jis tarah aaj is kitab ke barey mein kiya jaa raha hai jo tumhein di gayi hai). Agar tere Rubb ki taraf se ek baat pehle hi tai na kardi gayi hoti to in ikhtilaf karne walon ke darmiyan kabhi ka faisla chuka diya gaya hota. Yeh waqiya hai ke yeh log iski taraf se shakk aur khaljaan (disquieting doubt) mein padey huey hain" },
    { number: 111, arabic: "وَإِنَّ كُلًّۭا لَّمَّا لَيُوَفِّيَنَّهُمْ رَبُّكَ أَعْمَٰلَهُمْ ۚ إِنَّهُۥ بِمَا يَعْمَلُونَ خَبِيرٌۭ", transliteration: "Wainna kullan lamma layuwaffiyannahum rabbuka aAAmalahum innahu bima yaAAmaloona khabeerun", transliterationB: "Wa inna kullal lammaa la yuwaffiyannahum Rabbuka a'maalahum; innahoo bimaa ya'maloona Khabeer", english: "And, of a surety, to all will your Lord pay back (in full the recompense) of their deeds: for He knoweth well all that they do", romanUrdu: "Aur yeh bhi waqia hai ke tera Rabb inhein inke aamal ka poora poora badla de kar rahega. Yaqeenan woh inki sab harkaton se bakhabar hai" },
    { number: 112, arabic: "فَٱسْتَقِمْ كَمَآ أُمِرْتَ وَمَن تَابَ مَعَكَ وَلَا تَطْغَوْا۟ ۚ إِنَّهُۥ بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Faistaqim kama omirta waman taba maAAaka wala tatghaw innahu bima taAAmaloona baseerun", transliterationB: "Fastaqim kamaaa umirta wa man taaba ma'aka wa laa tatghaw; innahoo bimaa ta'maloona Baseer", english: "Therefore stand firm (in the straight Path) as thou art commanded,- thou and those who with thee turn (unto Allah); and transgress not (from the Path): for He seeth well all that ye do", romanUrdu: "Pas (aey Muhammad), tum aur tumhare woh saathi jo (kufr o bagawat se iman o itaat ki taraf) palat aaye hain, theek theek raah-e-raast par saabit qadam raho jaisa ke tumhein hukum diya gaya hai. Aur bandagi ki hadd se tajawuz na karo. Jo kuch tum kar rahey ho uspar tumhara Rubb nigaah rakhta hai" },
    { number: 113, arabic: "وَلَا تَرْكَنُوٓا۟ إِلَى ٱلَّذِينَ ظَلَمُوا۟ فَتَمَسَّكُمُ ٱلنَّارُ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِنْ أَوْلِيَآءَ ثُمَّ لَا تُنصَرُونَ", transliteration: "Wala tarkanoo ila allatheena thalamoo fatamassakumu alnnaru wama lakum min dooni Allahi min awliyaa thumma la tunsaroona", transliterationB: "Wa laa tarkanooo ilal lazeena zalamoo fatamassa kumun Naaru wa maa lakum min doonil laahi min awliyaaa'a summa laa tunsaroon", english: "And incline not to those who do wrong, or the Fire will seize you; and ye have no protectors other than Allah, nor shall ye be helped", romanUrdu: "In zaalimon ki taraf zara na jhukna warna jahannum ki lapeit mein aa jaaoge aur tumhein koi aisa wali o sarparast na milega jo khuda se tumhein bacha sakey aur kahin se tumko madad na pahunchegi" },
    { number: 114, arabic: "وَأَقِمِ ٱلصَّلَوٰةَ طَرَفَىِ ٱلنَّهَارِ وَزُلَفًۭا مِّنَ ٱلَّيْلِ ۚ إِنَّ ٱلْحَسَنَٰتِ يُذْهِبْنَ ٱلسَّيِّـَٔاتِ ۚ ذَٰلِكَ ذِكْرَىٰ لِلذَّٰكِرِينَ", transliteration: "Waaqimi alssalata tarafayi alnnahari wazulafan mina allayli inna alhasanati yuthhibna alssayyiati thalika thikra lilththakireena", transliterationB: "Wa aqimis Salaata tarafayin nahaari wa zulafam minal layl; innal hasanaati yuzhibnas saiyi aat; zaalika zikraa liz zaakireen", english: "And establish regular prayers at the two ends of the day and at the approaches of the night: For those things, that are good remove those that are evil: Be that the word of remembrance to those who remember (their Lord)", romanUrdu: "Aur dekho, namaz qayam karo din ke dono siron par (two ends of the day) aur kuch raat guzarne par. Dar haqeeqat nekiyan buraiyon ko door kar deti hain, yeh ek yaad dihani hai un logon ke liye jo khuda ko yaad rakhne waley hain" },
    { number: 115, arabic: "وَٱصْبِرْ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ", transliteration: "Waisbir fainna Allaha la yudeeAAu ajra almuhsineena", transliterationB: "Wasbir fa innal laaha laa yudee'u ajral muhsineen", english: "And be steadfast in patience; for verily Allah will not suffer the reward of the righteous to perish", romanUrdu: "Aur sabr kar, Allah neki karne walon ka ajar kabhi zaya nahin karta" },
    { number: 116, arabic: "فَلَوْلَا كَانَ مِنَ ٱلْقُرُونِ مِن قَبْلِكُمْ أُو۟لُوا۟ بَقِيَّةٍۢ يَنْهَوْنَ عَنِ ٱلْفَسَادِ فِى ٱلْأَرْضِ إِلَّا قَلِيلًۭا مِّمَّنْ أَنجَيْنَا مِنْهُمْ ۗ وَٱتَّبَعَ ٱلَّذِينَ ظَلَمُوا۟ مَآ أُتْرِفُوا۟ فِيهِ وَكَانُوا۟ مُجْرِمِينَ", transliteration: "Falawla kana mina alqurooni min qablikum oloo baqiyyatin yanhawna AAani alfasadi fee alardi illa qaleelan mimman anjayna minhum waittabaAAa allatheena thalamoo ma otrifoo feehi wakanoo mujrimeena", transliterationB: "Falw laa kaana minal qurooni min qablikum ooloo baqiyyatiny yanhawna 'anil fasaadi fil ardi illaa qaleelam mimman anjainaa minhum; wattaba'al lazeena zalamoo maaa utrifoo feehi wa kaanoo mujrimeen", english: "Why were there not, among the generations before you, persons possessed of balanced good sense, prohibiting (men) from mischief in the earth - except a few among them whom We saved (from harm)? But the wrong-doers pursued the enjoyment of the good things of life which were given them, and persisted in sin", romanUrdu: "Phir kyun na un qaumon mein jo tumse pehle guzar chuki hain aise ahle khair maujood rahey jo logon ko zameen mein fasaad barpa karne se rokte? Aisey log nikle bhi to bahut kam jinko humne un qaumon mein se bacha liya, warna zalim log to unhi mazon (ease and comfort) ke peechey padey rahey jinke samaan unhein farawani ke saath diye gaye thay (conferred upon them) aur woh mujreem bankar rahey" },
    { number: 117, arabic: "وَمَا كَانَ رَبُّكَ لِيُهْلِكَ ٱلْقُرَىٰ بِظُلْمٍۢ وَأَهْلُهَا مُصْلِحُونَ", transliteration: "Wama kana rabbuka liyuhlika alqura bithulmin waahluha muslihoona", transliterationB: "Wa maa kaana Rabbuka liyuhlikal quraa bizulminw wa ahluhaa muslihoon", english: "Nor would thy Lord be the One to destroy communities for a single wrong-doing, if its members were likely to mend", romanUrdu: "Tera Rubb aisa nahin hai ke bastiyon ko na-haqq tabah karde halanke unke bashinde islaah karne waley hon" },
    { number: 118, arabic: "وَلَوْ شَآءَ رَبُّكَ لَجَعَلَ ٱلنَّاسَ أُمَّةًۭ وَٰحِدَةًۭ ۖ وَلَا يَزَالُونَ مُخْتَلِفِينَ", transliteration: "Walaw shaa rabbuka lajaAAala alnnasa ommatan wahidatan wala yazaloona mukhtalifeena", transliterationB: "Wa law shaaa'a Rabbuka laja'alannnaasa ummatanw waa hidatanw wa laa yazaaloona mukhtalifeen", english: "If thy Lord had so willed, He could have made mankind one people: but they will not cease to dispute", romanUrdu: "Beshak tera Rubb agar chahta to tamaam Insaano ko ek giroh bana sakta tha, magar ab to woh mukhtalif tareeqon hi par chalte rahenge" },
    { number: 119, arabic: "إِلَّا مَن رَّحِمَ رَبُّكَ ۚ وَلِذَٰلِكَ خَلَقَهُمْ ۗ وَتَمَّتْ كَلِمَةُ رَبِّكَ لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ أَجْمَعِينَ", transliteration: "Illa man rahima rabbuka walithalika khalaqahum watammat kalimatu rabbika laamlaanna jahannama mina aljinnati waalnnasi ajmaAAeena", transliterationB: "Illaa mar rahima Rabbuk; wa lizaalika khalaqahum; wa tammat Kalimatu Rabbika la amla'ana Jahannama minal jinnati wannnaasi ajma'een", english: "Except those on whom thy Lord hath bestowed His Mercy: and for this did He create them: and the Word of thy Lord shall be fulfilled: \"I will fill Hell with jinns and men all together", romanUrdu: "Aur be raah-rawiyon se sirf woh log bachenge jinpar tere Rubb ki rehmat hai. Isi (azadi intekhab o ikhtiyar) ke liye hi to usne unhein paida kiya tha aur tere Rubb ki woh baat puri ho gayi jo usne kahi thi ke main jahannum ko Jinn aur Insaan, sabse bhar doonga" },
    { number: 120, arabic: "وَكُلًّۭا نَّقُصُّ عَلَيْكَ مِنْ أَنۢبَآءِ ٱلرُّسُلِ مَا نُثَبِّتُ بِهِۦ فُؤَادَكَ ۚ وَجَآءَكَ فِى هَٰذِهِ ٱلْحَقُّ وَمَوْعِظَةٌۭ وَذِكْرَىٰ لِلْمُؤْمِنِينَ", transliteration: "Wakullan naqussu AAalayka min anbai alrrusuli ma nuthabbitu bihi fuadaka wajaaka fee hathihi alhaqqu wamawAAithatun wathikra lilmumineena", transliterationB: "Wa kullan naqussu 'alaika min ambaaa'ir Rusuli maa nusabbitu bihee fu'aadak; wa jaaa'aka fee haazihil haqqu wa maw'izatunw wa zikraa lilmu' mineen", english: "All that we relate to thee of the stories of the messengers,- with it We make firm thy heart: in them there cometh to thee the Truth, as well as an exhortation and a message of remembrance to those who believe", romanUrdu: "Aur (Aey Muhammad), yeh paighambaron ke qissey jo hum tumhein sunate hain, woh cheezein hain jinke zariye se hum tumhare dil ko mazboot karte hain. Inke andar tumko haqeeqat ka ilam mila aur iman laney walon ko naseehat aur bedari naseeb hui" },
    { number: 121, arabic: "وَقُل لِّلَّذِينَ لَا يُؤْمِنُونَ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنَّا عَٰمِلُونَ", transliteration: "Waqul lillatheena la yuminoona iAAmaloo AAala makanatikum inna AAamiloona", transliterationB: "Wa qul lillazeena laa yu'minoona' maloo 'alaa makaanatikum innaa 'aamiloon", english: "Say to those who do not believe: \"Do what ever ye can: We shall do our part", romanUrdu: "Rahey woh log jo iman nahin latey, to unse kehdo ke tum apne tareeqe par kaam karte raho aur hum apne tareeqe par kiya jatey hain" },
    { number: 122, arabic: "وَٱنتَظِرُوٓا۟ إِنَّا مُنتَظِرُونَ", transliteration: "Waintathiroo inna muntathiroona", transliterationB: "Wantaziroo innaa mun taziroon", english: "And wait ye! We too shall wait", romanUrdu: "Anjaam e kaar ka tum bhi intezaar karo aur hum bhi muntazir(waiting) hain" },
    { number: 123, arabic: "وَلِلَّهِ غَيْبُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَإِلَيْهِ يُرْجَعُ ٱلْأَمْرُ كُلُّهُۥ فَٱعْبُدْهُ وَتَوَكَّلْ عَلَيْهِ ۚ وَمَا رَبُّكَ بِغَٰفِلٍ عَمَّا تَعْمَلُونَ", transliteration: "Walillahi ghaybu alssamawati waalardi wailayhi yurjaAAu alamru kulluhu faoAAbudhu watawakkal AAalayhi wama rabbuka bighafilin AAamma taAAmaloona", transliterationB: "Wa lillaahi ghaibus samaawaati wal ardi wa ilaihi yurja'ul amru kulluhoo fa'bu-dhu wa tawakkal 'alaih; wa maa Rabbuka bighaafilin 'ammaa ta'maloon", english: "To Allah do belong the unseen (secrets) of the heavens and the earth, and to Him goeth back every affair (for decision): then worship Him, and put thy trust in Him: and thy Lord is not unmindful of aught that ye do", romanUrdu: "Aasmaano aur zameen mein jo kuch chupa hua hai sab Allah ke qabze qudrat mein hai. Aur sara maamla usi ki taraf rujoo kiya jata hai. Pas (aey Nabi) tu uski bandagi kar aur usi par bharosa rakh. Jo kuch tumlog kar rahey ho tera Rubb ussey bekhabar nahin hai" }
  ]
};
